export default function Stock() {
  const [searchQuery, setSearchQuery] = useState("");
  const [categoryFilter, setCategoryFilter] = useState("all");
  const [packTypeFilter, setPackTypeFilter] = useState("all");
  const [stockStatusFilter, setStockStatusFilter] = useState("all");
  const [partyFilter, setPartyFilter] = useState("all");
  const [itemFilter, setItemFilter] = useState("all");
  const [viewMode, setViewMode] = useState<"list" | "grid">("list");
  const [selectedItemId, setSelectedItemId] = useState<number | null>(null);
  const [historyDialogOpen, setHistoryDialogOpen] = useState(false);
  const [showItemSearch, setShowItemSearch] = useState(false);
  const printRef = useRef<HTMLDivElement>(null);
  const { currentCompany } = useCompany();

  // Fetch parties list
  const { data: parties } = useQuery<Party[]>({
    queryKey: ["/api/parties"],
  });

  // Build query params
  const queryParams = new URLSearchParams();
  if (partyFilter !== "all") queryParams.set("partyId", partyFilter);
  if (itemFilter !== "all") queryParams.set("itemId", itemFilter);

  const queryString = queryParams.toString();
  const apiUrl = queryString ? `/api/stock?${queryString}` : "/api/stock";

  const { data: stock, isLoading } = useQuery<StockItem[]>({
    queryKey: ["/api/stock", partyFilter, itemFilter],
    queryFn: async () => {
      const res = await fetch(apiUrl, { credentials: "include", headers: { "X-Company-Id": localStorage.getItem("currentCompanyId") || "" } });
      if (!res.ok) throw new Error("Failed to fetch stock");
      return res.json();
    },
  });

  const handlePrint = useReactToPrint({
    contentRef: printRef,
    documentTitle: `Stock-Report-${format(new Date(), "yyyy-MM-dd")}`,
  });

  // Get unique values for filters from fetched data
  const categories = Array.from(new Set(stock?.map(item => item.category).filter(Boolean))).sort();
  const packTypes = Array.from(new Set(stock?.map(item => item.packType))).sort();
  const items = Array.from(new Set(stock?.map(item => item.itemId))).map(itemId => {
    const item = stock?.find(s => s.itemId === itemId);
    return item ? { id: item.itemId, code: item.itemCode, name: item.itemName } : null;
  }).filter(Boolean).sort((a, b) => (a?.code || "").localeCompare(b?.code || ""));

  const filteredStock = stock?.filter((item) => {
    // Text search
    const matchesSearch = 
      item.itemName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.itemCode.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.category?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      item.partyName?.toLowerCase().includes(searchQuery.toLowerCase());

    // Category filter
    const matchesCategory = categoryFilter === "all" || item.category === categoryFilter;

    // Pack type filter
    const matchesPackType = packTypeFilter === "all" || item.packType === packTypeFilter;

    // Stock status filter
    const qty = parseFloat(item.quantity);
    let matchesStatus = true;
    if (stockStatusFilter === "instock") matchesStatus = qty > 10;
    else if (stockStatusFilter === "low") matchesStatus = qty > 0 && qty <= 10;
    else if (stockStatusFilter === "out") matchesStatus = qty === 0;

    return matchesSearch && matchesCategory && matchesPackType && matchesStatus;
  });

  const lowStockItems = filteredStock?.filter(item => parseFloat(item.quantity) < 10 && parseFloat(item.quantity) > 0) || [];
  const outOfStockItems = filteredStock?.filter(item => parseFloat(item.quantity) === 0) || [];

  const totals = {
    totalItems: filteredStock?.length || 0,
    totalQty: filteredStock?.reduce((sum, item) => sum + parseFloat(item.quantity), 0) || 0,
    totalValue: filteredStock?.reduce((sum, item) => sum + (parseFloat(item.quantity) * parseFloat(item.cost)), 0) || 0,
  };

  const activeFilters = [
    partyFilter !== "all" ? `Party: ${parties?.find(p => p.id.toString() === partyFilter)?.name}` : null,
    itemFilter !== "all" ? `Item: ${items.find(i => i?.id.toString() === itemFilter)?.name}` : null,
    categoryFilter !== "all" ? `Category: ${categoryFilter}` : null,
    packTypeFilter !== "all" ? `Pack: ${packTypeFilter}` : null,
    stockStatusFilter !== "all" ? `Status: ${stockStatusFilter}` : null,
  ].filter(Boolean).join(", ");

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Stock Inventory</h1>
          <p className="text-muted-foreground mt-2">
            View and analyze current stock levels
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="icon" onClick={() => setViewMode(viewMode === "list" ? "grid" : "list")}>
            {viewMode === "list" ? <Grid className="h-4 w-4" /> : <List className="h-4 w-4" />}
          </Button>
          <Button onClick={() => handlePrint()} disabled={!filteredStock?.length} data-testid="button-print-stock">
            <Printer className="h-4 w-4 mr-2" />
            Print
          </Button>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid gap-6 sm:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Items</CardTitle>
            <Package className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold font-mono" data-testid="text-total-items">
              {totals.totalItems}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Quantity</CardTitle>
            <BarChart2 className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold font-mono" data-testid="text-total-qty">
              {totals.totalQty.toFixed(2)}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Stock Value</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold font-mono" data-testid="text-stock-value">
              ₹{totals.totalValue.toFixed(2)}
            </div>
          </CardContent>
        </Card>

        <Card className={lowStockItems.length + outOfStockItems.length > 0 ? "border-orange-200 dark:border-orange-900" : ""}>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Alerts</CardTitle>
            <AlertCircle className="h-4 w-4 text-orange-600" />
          </CardHeader>
          <CardContent>
            <div className="text-sm">
              <span className="text-orange-600 font-medium">{lowStockItems.length}</span> Low Stock
              <span className="mx-2">|</span>
              <span className="text-red-600 font-medium">{outOfStockItems.length}</span> Out of Stock
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      <Card>
        <CardHeader>
          <CardTitle>Filters</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 sm:grid-cols-6">
            <div className="space-y-2 sm:col-span-2">
              <Label htmlFor="search">Search</Label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  id="search"
                  placeholder="Search by name, code, party..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9"
                  data-testid="input-search-stock"
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="party">Supplier</Label>
              <Select value={partyFilter} onValueChange={setPartyFilter}>
                <SelectTrigger id="party" data-testid="select-party">
                  <SelectValue placeholder="All Suppliers" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Suppliers</SelectItem>
                  {parties?.map((party) => (
                    <SelectItem key={party.id} value={party.id.toString()}>
                      {party.code} - {party.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="item">Item</Label>
              <Button
                type="button"
                variant="outline"
                className="w-full justify-start text-left h-9"
                onClick={() => setShowItemSearch(true)}
                data-testid="button-search-stock-item"
              >
                {itemFilter && itemFilter !== "all" 
                  ? items.find(i => i?.id.toString() === itemFilter)?.name 
                  : "All Items"}
              </Button>
            </div>
            <div className="space-y-2">
              <Label htmlFor="category">Category</Label>
              <Select value={categoryFilter} onValueChange={setCategoryFilter}>
                <SelectTrigger id="category" data-testid="select-category">
                  <SelectValue placeholder="All Categories" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Categories</SelectItem>
                  {categories.map((cat) => (
                    <SelectItem key={cat} value={cat!}>{cat}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="packType">Pack Type</Label>
              <Select value={packTypeFilter} onValueChange={setPackTypeFilter}>
                <SelectTrigger id="packType" data-testid="select-pack-type">
                  <SelectValue placeholder="All Pack Types" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Pack Types</SelectItem>
                  {packTypes.map((pt) => (
                    <SelectItem key={pt} value={pt}>{pt}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="status">Stock Status</Label>
              <Select value={stockStatusFilter} onValueChange={setStockStatusFilter}>
                <SelectTrigger id="status" data-testid="select-status">
                  <SelectValue placeholder="All Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Status</SelectItem>
                  <SelectItem value="instock">In Stock (&gt;10)</SelectItem>
                  <SelectItem value="low">Low Stock (1-10)</SelectItem>
                  <SelectItem value="out">Out of Stock</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Stock List */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between gap-4">
            <CardTitle>Stock List</CardTitle>
            {activeFilters && (
              <Badge variant="outline" className="text-xs">
                {activeFilters}
              </Badge>
            )}
          </div>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-3">
              {[...Array(5)].map((_, i) => (
                <Skeleton key={i} className="h-12 w-full" />
              ))}
            </div>
          ) : viewMode === "list" ? (
            filteredStock && filteredStock.length > 0 ? (
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Code</TableHead>
                    <TableHead>Item Name</TableHead>
                    <TableHead>Supplier</TableHead>
                    <TableHead>Category</TableHead>
                    <TableHead>Pack Type</TableHead>
                    <TableHead className="text-right">Rate</TableHead>
                    <TableHead className="text-right">Quantity</TableHead>
                    <TableHead className="text-right">Value</TableHead>
                    <TableHead className="text-center">Status</TableHead>
                    <TableHead className="text-center">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredStock.map((item) => {
                    const qty = parseFloat(item.quantity);
                    const isLow = qty < 10 && qty > 0;
                    const isOut = qty === 0;
                    const value = qty * parseFloat(item.cost);

                    return (
                      <TableRow key={item.stockInwardId} data-testid={`row-stock-${item.stockInwardId}`}>
                        <TableCell className="font-medium font-mono">{item.itemCode}</TableCell>
                        <TableCell>{item.itemName}</TableCell>
                        <TableCell className="text-muted-foreground">{item.partyName || "—"}</TableCell>
                        <TableCell className="text-muted-foreground">{item.category || "—"}</TableCell>
                        <TableCell className="font-mono">{item.packType}</TableCell>
                        <TableCell className="text-right font-mono">
                          ₹{parseFloat(item.cost).toFixed(2)}
                        </TableCell>
                        <TableCell className="text-right font-mono font-medium">
                          {qty.toFixed(3)}
                        </TableCell>
                        <TableCell className="text-right font-mono">
                          ₹{value.toFixed(2)}
                        </TableCell>
                        <TableCell className="text-center">
                          {isOut ? (
                            <Badge variant="destructive" className="text-xs">Out of Stock</Badge>
                          ) : isLow ? (
                            <Badge variant="secondary" className="text-xs bg-orange-100 text-orange-800 dark:bg-orange-950 dark:text-orange-200">Low Stock</Badge>
                          ) : (
                            <Badge variant="default" className="text-xs">In Stock</Badge>
                          )}
                        </TableCell>
                        <TableCell className="text-center">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => {
                              setSelectedItemId(item.itemId);
                              setHistoryDialogOpen(true);
                            }}
                            data-testid={`button-view-history-${item.stockInwardId}`}
                          >
                            <Eye className="h-4 w-4" />
                          </Button>
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-center">
                <Package className="h-12 w-12 text-muted-foreground/50 mb-4" />
                <p className="text-sm text-muted-foreground mb-1">
                  {searchQuery || categoryFilter !== "all" || packTypeFilter !== "all" || stockStatusFilter !== "all" 
                    ? "No items found matching filters" 
                    : "No stock data available"}
                </p>
              </div>
            )
          ) : (
            // Grid view
            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
              {filteredStock?.map((item) => {
                const qty = parseFloat(item.quantity);
                const isLow = qty < 10 && qty > 0;
                const isOut = qty === 0;
                const value = qty * parseFloat(item.cost);

                return (
                  <Card key={item.stockInwardId} className={`${isOut ? 'border-red-200' : isLow ? 'border-orange-200' : ''}`}>
                    <CardContent className="pt-4">
                      <div className="flex justify-between items-start mb-2">
                        <div>
                          <p className="font-mono text-xs text-muted-foreground">{item.itemCode}</p>
                          <h3 className="font-medium">{item.itemName}</h3>
                          <p className="text-xs text-muted-foreground">{item.partyName || "—"}</p>
                        </div>
                        <div className="flex items-center gap-2">
                          {isOut ? (
                            <Badge variant="destructive" className="text-xs">Out</Badge>
                          ) : isLow ? (
                            <Badge variant="secondary" className="text-xs bg-orange-100 text-orange-800">Low</Badge>
                          ) : (
                            <Badge variant="default" className="text-xs">OK</Badge>
                          )}
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => {
                              setSelectedItemId(item.itemId);
                              setHistoryDialogOpen(true);
                            }}
                            data-testid={`button-view-history-grid-${item.stockInwardId}`}
                          >
                            <Eye className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                      <div className="grid grid-cols-2 gap-2 text-sm">
                        <div>
                          <p className="text-muted-foreground text-xs">Category</p>
                          <p>{item.category || "—"}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Pack</p>
                          <p>{item.packType}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Quantity</p>
                          <p className="font-mono font-medium">{qty.toFixed(3)}</p>
                        </div>
                        <div>
                          <p className="text-muted-foreground text-xs">Value</p>
                          <p className="font-mono">₹{value.toFixed(2)}</p>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Hidden print container */}
      <div style={{ position: 'absolute', left: '-9999px', top: '0' }}>
        <div ref={printRef}>
          <StockReportPrint
            items={filteredStock || []}
            totals={totals}
            companyName={currentCompany?.name || "Company"}
            filters={activeFilters}
          />
        </div>
      </div>

      {/* Item History Dialog */}
      <ItemHistoryDialog
        itemId={selectedItemId}
        isOpen={historyDialogOpen}
        onClose={() => {
          setHistoryDialogOpen(false);
          setSelectedItemId(null);
        }}
      />

      <ItemSearchModal
        open={showItemSearch}
        items={items.filter((i): i is Item => i !== null)}
        isLoading={false}
        onSelect={(item) => {
          setItemFilter(item.id.toString());
          setShowItemSearch(false);
        }}
        onClose={() => setShowItemSearch(false)}
        title="Search & Select Item"
      />
    </div>
  );
}

client/src/pages/sales.tsx.content:
import { useState, useRef } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Plus, Search, FileText, Filter, Printer, Eye, Edit, Trash2, FileCheck, Download, QrCode } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";
import { Link, useLocation } from "wouter";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { useReactToPrint } from "react-to-print";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";

interface Sale {
  id: number;
  invoiceNo: number;
  billType: string;
  saleType: string;
  date: string;
  partyName: string | null;
  partyCity: string | null;
  grandTotal: string;
  totalQty: string;
  gstType: number;
  einvoiceStatus: string | null;
  irn: string | null;
  ackNumber: string | null;
  ackDate: string | null;
  qrCode: string | null;
}

export default function Sales() {
  const [searchQuery, setSearchQuery] = useState("");
  const [dateFilter, setDateFilter] = useState("");
  const [saleTypeFilter, setSaleTypeFilter] = useState<string>("all");
  const [, setLocation] = useLocation();
  const printRef = useRef<HTMLDivElement>(null);
  const { user } = useAuth();
  const { toast } = useToast();
  const canDeleteBill = user?.role === "admin" || user?.role === "superadmin";

  // E-Invoice dialog state
  const [einvoiceDialogOpen, setEinvoiceDialogOpen] = useState(false);
  const [selectedSaleForEinvoice, setSelectedSaleForEinvoice] = useState<Sale | null>(null);
  const [einvoiceForm, setEinvoiceForm] = useState({
    irn: "",
    ackNumber: "",
    ackDate: "",
    qrCode: "",
  });

  const { data: sales, isLoading } = useQuery<Sale[]>({
    queryKey: ["/api/sales"],
  });

  const deleteMutation = useMutation({
    mutationFn: async (saleId: number) => {
      const response = await apiRequest("DELETE", `/api/sales/${saleId}`);
      if (!response.ok) throw new Error("Failed to delete sale");
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Success",
        description: "Sale deleted successfully",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/sales"] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete sale",
        variant: "destructive",
      });
    },
  });

  const handleDeleteSale = (saleId: number) => {
    if (window.confirm("Are you sure you want to delete this sale?")) {
      deleteMutation.mutate(saleId);
    }
  };

  // E-Invoice mutation
  const einvoiceMutation = useMutation({
    mutationFn: async (data: { saleId: number; einvoiceData: typeof einvoiceForm }) => {
      const response = await apiRequest("PATCH", `/api/sales/${data.saleId}/einvoice`, data.einvoiceData);
      if (!response.ok) throw new Error("Failed to update e-invoice details");
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Success",
        description: "E-Invoice details saved successfully",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/sales"] });
      setEinvoiceDialogOpen(false);
      setSelectedSaleForEinvoice(null);
      setEinvoiceForm({ irn: "", ackNumber: "", ackDate: "", qrCode: "" });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to save e-invoice details",
        variant: "destructive",
      });
    },
  });

  const openEinvoiceDialog = (sale: Sale) => {
    setSelectedSaleForEinvoice(sale);
    setEinvoiceForm({
      irn: sale.irn || "",
      ackNumber: sale.ackNumber || "",
      ackDate: sale.ackDate ? format(new Date(sale.ackDate), "yyyy-MM-dd'T'HH:mm") : "",
      qrCode: sale.qrCode || "",
    });
    setEinvoiceDialogOpen(true);
  };

  const handleDownloadEinvoiceJson = async (saleId: number) => {
    try {
      const response = await fetch(`/api/sales/${saleId}/einvoice-json`, {
        credentials: 'include',
      });
      if (!response.ok) throw new Error("Failed to generate e-invoice JSON");
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `einvoice-${saleId}.json`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
      toast({
        title: "Success",
        description: "E-Invoice JSON downloaded",
      });
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to download e-invoice JSON",
        variant: "destructive",
      });
    }
  };

  const handleSaveEinvoice = () => {
    if (!selectedSaleForEinvoice) return;
    einvoiceMutation.mutate({
      saleId: selectedSaleForEinvoice.id,
      einvoiceData: einvoiceForm,
    });
  };

  const filteredSales = sales?.filter((sale) => {
    const matchesSearch = 
      sale.invoiceNo.toString().includes(searchQuery) ||
      sale.partyName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      sale.saleType?.toLowerCase().includes(searchQuery.toLowerCase());

    const matchesDate = !dateFilter || sale.date === dateFilter;

    const matchesSaleType = saleTypeFilter === "all" || sale.saleType === saleTypeFilter;

    return matchesSearch && matchesDate && matchesSaleType;
  });

  const totalAmount = filteredSales?.reduce((sum, sale) => sum + parseFloat(sale.grandTotal), 0) || 0;
  const totalQty = filteredSales?.reduce((sum, sale) => sum + parseFloat(sale.totalQty), 0) || 0;

  const getSaleTypeBadgeVariant = (saleType: string): "default" | "secondary" | "outline" => {
    if (saleType === "B2B") return "default";
    if (saleType === "B2C") return "secondary";
    return "outline";
  };

  const handlePrintList = useReactToPrint({
    contentRef: printRef,
    documentTitle: `Sales-List-${format(new Date(), "yyyy-MM-dd")}`,
  });

  const openInvoice = (saleId: number, skipDirectPrint: boolean = true) => {
    const params = skipDirectPrint ? '?no-direct-print=true' : '';
    window.open(`/invoice/${saleId}${params}`, '_blank');
  };

  return (
    <div className="p-3 sm:p-6 space-y-4 sm:space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div>
          <h1 className="text-2xl sm:text-3xl font-semibold tracking-tight">Sales Invoices</h1>
          <p className="text-sm sm:text-base text-muted-foreground mt-1 sm:mt-2">
            View and manage all sales transactions
          </p>
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <Button variant="outline" onClick={() => handlePrintList()} data-testid="button-print-list" size="sm" className="flex-1 sm:flex-none">
            <Printer className="mr-1 sm:mr-2 h-4 w-4" />
            <span className="hidden sm:inline">Print List</span>
            <span className="sm:hidden">Print</span>
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <CardTitle>Invoice List</CardTitle>
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
              <Select value={saleTypeFilter} onValueChange={setSaleTypeFilter}>
                <SelectTrigger className="w-full sm:w-40" data-testid="select-sale-type-filter">
                  <Filter className="mr-2 h-4 w-4" />
                  <SelectValue placeholder="All Types" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Types</SelectItem>
                  <SelectItem value="B2B">B2B (Credit)</SelectItem>
                  <SelectItem value="B2C">B2C (Cash/Retail)</SelectItem>
                  <SelectItem value="ESTIMATE">Estimate</SelectItem>
                </SelectContent>
              </Select>
              <div className="relative w-full sm:w-64">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Search invoices..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9"
                  data-testid="input-search-sales"
                />
              </div>
              <Input
                type="date"
                value={dateFilter}
                onChange={(e) => setDateFilter(e.target.value)}
                className="w-full sm:w-48"
                data-testid="input-filter-date"
              />
            </div>
          </div>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-3">
              {[...Array(5)].map((_, i) => (
                <Skeleton key={i} className="h-12 w-full" />
              ))}
            </div>
          ) : filteredSales && filteredSales.length > 0 ? (
            <>
              <div ref={printRef}>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Invoice No</TableHead>
                      <TableHead>Date</TableHead>
                      <TableHead>Type</TableHead>
                      <TableHead>Customer</TableHead>
                      <TableHead>City</TableHead>
                      <TableHead className="text-right">Qty</TableHead>
                      <TableHead className="text-right">Amount</TableHead>
                      <TableHead className="print:hidden">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredSales.map((sale) => (
                      <TableRow key={sale.id}>
                        <TableCell className="font-medium font-mono">
                          {sale.saleType}-{sale.invoiceNo}
                        </TableCell>
                        <TableCell>{format(new Date(sale.date), "dd MMM yyyy")}</TableCell>
                        <TableCell>
                          <Badge variant={getSaleTypeBadgeVariant(sale.saleType)}>
                            {sale.saleType}
                          </Badge>
                        </TableCell>
                        <TableCell>{sale.partyName || "Cash Sale"}</TableCell>
                        <TableCell className="text-muted-foreground">{sale.partyCity || "—"}</TableCell>
                        <TableCell className="text-right font-mono">{parseFloat(sale.totalQty).toFixed(2)}</TableCell>
                        <TableCell className="text-right font-mono font-medium">
                          ₹{parseFloat(sale.grandTotal).toFixed(2)}
                        </TableCell>
                        <TableCell className="print:hidden">
                          <div className="flex gap-1">
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => openInvoice(sale.id)}
                              title="View & Print Invoice"
                              data-testid={`button-view-invoice-${sale.id}`}
                            >
                              <Eye className="h-4 w-4" />
                            </Button>
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => setLocation(`/sales/edit/${sale.id}`)}
                              title="Edit Invoice"
                              data-testid={`button-edit-invoice-${sale.id}`}
                            >
                              <Edit className="h-4 w-4" />
                            </Button>
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => openInvoice(sale.id)}
                              title="Reprint Invoice"
                              data-testid={`button-reprint-invoice-${sale.id}`}
                            >
                              <Printer className="h-4 w-4" />
                            </Button>
                            {canDeleteBill && (sale.saleType === "B2C" || sale.saleType === "ESTIMATE") && (
                              <Button
                                size="icon"
                                variant="ghost"
                                onClick={() => handleDeleteSale(sale.id)}
                                title="Delete Sale"
                                data-testid={`button-delete-sale-${sale.id}`}
                                disabled={deleteMutation.isPending}
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            )}
                            {sale.saleType === "B2B" && (
                              <>
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  onClick={() => handleDownloadEinvoiceJson(sale.id)}
                                  title="Download e-Invoice JSON"
                                  data-testid={`button-download-einvoice-${sale.id}`}
                                >
                                  <Download className="h-4 w-4" />
                                </Button>
                                <Button
                                  size="icon"
                                  variant={sale.irn ? "default" : "ghost"}
                                  onClick={() => openEinvoiceDialog(sale)}
                                  title={sale.irn ? "e-Invoice Generated" : "Enter e-Invoice Response"}
                                  data-testid={`button-einvoice-${sale.id}`}
                                  className={sale.irn ? "bg-green-600 hover:bg-green-700 text-white" : ""}
                                >
                                  {sale.irn ? <FileCheck className="h-4 w-4" /> : <QrCode className="h-4 w-4" />}
                                </Button>
                              </>
                            )}
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
                <div className="mt-4 flex justify-between items-center border-t pt-4">
                  <p className="text-sm text-muted-foreground">
                    Showing {filteredSales.length} invoice{filteredSales.length !== 1 ? "s" : ""}
                  </p>
                  <div className="flex items-center gap-4">
                    <span className="text-sm text-muted-foreground">Total Qty: <span className="font-mono font-medium">{totalQty.toFixed(2)}</span></span>
                    <span className="text-sm text-muted-foreground">Total:</span>
                    <span className="text-lg font-semibold font-mono" data-testid="text-total-amount">
                      ₹{totalAmount.toFixed(2)}
                    </span>
                  </div>
                </div>
              </div>
            </>
          ) : (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <FileText className="h-12 w-12 text-muted-foreground/50 mb-4" />
              <p className="text-sm text-muted-foreground mb-1">
                {searchQuery || dateFilter ? "No invoices found" : "No sales yet"}
              </p>
              {!searchQuery && !dateFilter && (
                <Button asChild className="mt-4" size="sm">
                  <Link href="/sales/new" data-testid="button-create-first-invoice">Create First Invoice</Link>
                </Button>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* E-Invoice Dialog */}
      <Dialog open={einvoiceDialogOpen} onOpenChange={setEinvoiceDialogOpen}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle>E-Invoice Details</DialogTitle>
            <DialogDescription>
              Enter the e-Invoice response data from the GST portal after uploading the JSON.
              Invoice: {selectedSaleForEinvoice?.saleType}-{selectedSaleForEinvoice?.invoiceNo}
            </DialogDescription>
          </DialogHeader>
          <div className="grid gap-4 py-4">
            <div className="grid gap-2">
              <Label htmlFor="irn">IRN (Invoice Reference Number)</Label>
              <Input
                id="irn"
                placeholder="Enter IRN from GST portal"
                value={einvoiceForm.irn}
                onChange={(e) => setEinvoiceForm({ ...einvoiceForm, irn: e.target.value })}
                data-testid="input-einvoice-irn"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="ackNumber">Acknowledgement Number</Label>
              <Input
                id="ackNumber"
                placeholder="Enter acknowledgement number"
                value={einvoiceForm.ackNumber}
                onChange={(e) => setEinvoiceForm({ ...einvoiceForm, ackNumber: e.target.value })}
                data-testid="input-einvoice-ack-number"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="ackDate">Acknowledgement Date & Time</Label>
              <Input
                id="ackDate"
                type="datetime-local"
                value={einvoiceForm.ackDate}
                onChange={(e) => setEinvoiceForm({ ...einvoiceForm, ackDate: e.target.value })}
                data-testid="input-einvoice-ack-date"
              />
            </div>
            <div className="grid gap-2">
              <Label htmlFor="qrCode">QR Code Data</Label>
              <Textarea
                id="qrCode"
                placeholder="Paste the QR code data from e-Invoice response"
                value={einvoiceForm.qrCode}
                onChange={(e) => setEinvoiceForm({ ...einvoiceForm, qrCode: e.target.value })}
                rows={4}
                data-testid="input-einvoice-qr-code"
              />
              <p className="text-xs text-muted-foreground">
                This QR code will be printed on your invoice
              </p>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEinvoiceDialogOpen(false)}>
              Cancel
            </Button>
            <Button 
              onClick={handleSaveEinvoice}
              disabled={einvoiceMutation.isPending}
              data-testid="button-save-einvoice"
            >
              {einvoiceMutation.isPending ? "Saving..." : "Save E-Invoice Details"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/components/ui/tooltip.tsx.content:
"use client"

import * as React from "react"
import * as TooltipPrimitive from "@radix-ui/react-tooltip"

import { cn } from "@/lib/utils"

const TooltipProvider = TooltipPrimitive.Provider

const Tooltip = TooltipPrimitive.Root

const TooltipTrigger = TooltipPrimitive.Trigger

const TooltipContent = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>
>(({ className, sideOffset = 4, ...props }, ref) => (
  <TooltipPrimitive.Content
    ref={ref}
    sideOffset={sideOffset}
    className={cn(
