                    <TableCell className="text-right font-mono">{item.invoiceCount}</TableCell>
                    <TableCell className="text-right font-mono">
                      {parseFloat(item.totalQty).toFixed(3)}
                    </TableCell>
                    <TableCell className="text-right font-mono">
                      ₹{parseFloat(item.totalSaleValue).toFixed(2)}
                    </TableCell>
