                      Clear Form
                    </Button>
                    <Button
                      type="submit"
                      disabled={createPurchaseMutation.isPending || !selectedPartyId}
                      data-testid="button-save"
                    >
                      <Plus className="mr-2 h-4 w-4" />
                      {createPurchaseMutation.isPending ? "Creating..." : "Create Entry"}
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>

            <Card className="bg-muted/50">
              <CardContent className="pt-6">
                <div className="flex items-start gap-4">
                  <div className="p-3 bg-primary/10 rounded-lg">
                    <Truck className="h-6 w-6 text-primary" />
                  </div>
                  <div>
                    <h3 className="font-semibold">Two-Phase Purchase Workflow</h3>
                    <p className="text-sm text-muted-foreground mt-1">
                      <strong>Phase 1 (This Page):</strong> Enter bill outline details - supplier, date, bill number, amounts, GST.<br />
                      <strong>Phase 2 (Stock Inward):</strong> Select a pending entry and add detailed item information with barcode generation.
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="pending" className="mt-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-4">
                <CardTitle>Pending for Stock Inward</CardTitle>
                <Button asChild size="sm" data-testid="button-stock-inward">
                  <Link href="/stock-inward">
                    <Package className="mr-2 h-4 w-4" />
                    Open Stock Inward
                  </Link>
                </Button>
              </CardHeader>
              <CardContent>
                {pendingLoading ? (
                  <div className="text-center py-8 text-muted-foreground">Loading pending entries...</div>
                ) : pendingPurchases && pendingPurchases.length > 0 ? (
                  <div className="border rounded-md overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Entry No</TableHead>
                          <TableHead>Date</TableHead>
                          <TableHead>Invoice No</TableHead>
                          <TableHead>Supplier</TableHead>
                          <TableHead>City</TableHead>
                          <TableHead className="text-right">Amount</TableHead>
                          <TableHead>Status</TableHead>
                          <TableHead className="text-center">Action</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {pendingPurchases.map((purchase) => (
                          <TableRow key={purchase.id} data-testid={`row-pending-${purchase.id}`}>
                            <TableCell>
                              <Badge variant="outline">{purchase.purchaseNo}</Badge>
                            </TableCell>
                            <TableCell>
                              {purchase.date ? format(new Date(purchase.date), "dd/MM/yyyy") : "-"}
                            </TableCell>
                            <TableCell>{purchase.invoiceNo || "-"}</TableCell>
                            <TableCell>{purchase.partyName || "-"}</TableCell>
                            <TableCell>{purchase.city || "-"}</TableCell>
                            <TableCell className="text-right">
                              ₹{parseFloat(purchase.amount || "0").toFixed(2)}
                            </TableCell>
                            <TableCell>
                              <Badge variant="secondary">Pending Stock Inward</Badge>
                            </TableCell>
                            <TableCell className="text-center">
                              <Button variant="default" size="sm" asChild data-testid={`button-inward-${purchase.id}`}>
                                <Link href={`/stock-inward?purchaseId=${purchase.id}`}>
                                  <Package className="mr-1 h-4 w-4" />
                                  Add Items
                                </Link>
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    No pending entries. Create a new purchase entry to start.
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="list" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>All Purchases</CardTitle>
              </CardHeader>
              <CardContent>
                {purchasesLoading ? (
                  <div className="text-center py-8 text-muted-foreground">Loading purchases...</div>
                ) : purchases && purchases.length > 0 ? (
                  <div className="border rounded-md overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Purchase No</TableHead>
                          <TableHead>Date</TableHead>
                          <TableHead>Invoice No</TableHead>
                          <TableHead>Party Name</TableHead>
                          <TableHead>City</TableHead>
                          <TableHead className="text-right">Qty</TableHead>
                          <TableHead className="text-right">Amount</TableHead>
                          <TableHead>Status</TableHead>
                          <TableHead className="text-center">Actions</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {purchases.map((purchase) => (
                          <TableRow key={purchase.id} data-testid={`row-purchase-${purchase.id}`}>
                            <TableCell>
                              <Badge variant="outline">{purchase.purchaseNo}</Badge>
                            </TableCell>
                            <TableCell>
                              {purchase.date ? format(new Date(purchase.date), "dd/MM/yyyy") : "-"}
                            </TableCell>
                            <TableCell>{purchase.invoiceNo || "-"}</TableCell>
                            <TableCell>{purchase.partyName || "-"}</TableCell>
                            <TableCell>{purchase.city || "-"}</TableCell>
                            <TableCell className="text-right">{parseFloat(purchase.totalQty || "0").toFixed(2)}</TableCell>
                            <TableCell className="text-right">₹{parseFloat(purchase.amount || "0").toFixed(2)}</TableCell>
                            <TableCell>
                              {purchase.stockInwardCompleted ? (
                                <Badge variant="default">Completed</Badge>
                              ) : purchase.isTallied === false ? (
                                <Badge variant="destructive" data-testid={`badge-not-tallied-${purchase.id}`}>Not Tallied</Badge>
                              ) : (
                                <Badge variant="secondary">Pending</Badge>
                              )}
                            </TableCell>
                            <TableCell className="text-center flex gap-2 justify-center">
                              <Button 
                                variant="ghost" 
                                size="sm" 
                                onClick={() => {
                                  setSelectedPurchaseForEdit(purchase);
                                  setActiveTab("edit");
                                }}
                                data-testid={`button-edit-${purchase.id}`}
                              >
                                <Edit className="mr-1 h-4 w-4" />
                                Edit Items
                              </Button>
                              <Button variant="ghost" size="sm" asChild data-testid={`button-view-${purchase.id}`}>
                                <Link href={`/purchases/${purchase.id}`}>
                                  <Eye className="mr-1 h-4 w-4" />
                                  View
                                </Link>
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    No purchases found. Create your first purchase entry.
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="edit" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>Edit Stock Inward Items</CardTitle>
              </CardHeader>
              <CardContent>
                {selectedPurchaseForEdit ? (
                  <div className="space-y-4">
                    <div className="grid grid-cols-4 gap-4 bg-muted p-4 rounded-lg">
                      <div>
                        <Label className="text-xs">Purchase No</Label>
                        <p className="font-semibold">#{selectedPurchaseForEdit.purchaseNo}</p>
                      </div>
                      <div>
                        <Label className="text-xs">Invoice No</Label>
                        <p className="font-semibold">{selectedPurchaseForEdit.invoiceNo || "-"}</p>
                      </div>
                      <div>
                        <Label className="text-xs">Supplier</Label>
                        <p className="font-semibold">{selectedPurchaseForEdit.partyName}</p>
                      </div>
                      <div className="text-right">
                        <Label className="text-xs">Amount</Label>
                        <p className="font-semibold">₹{parseFloat(selectedPurchaseForEdit.amount || "0").toFixed(2)}</p>
                      </div>
                    </div>
                    <div className="border-t pt-4">
                      <Button 
                        asChild 
                        className="w-full"
                        size="lg"
                        data-testid="button-go-to-stock-inward"
                      >
                        <Link href={`/stock-inward?purchaseId=${selectedPurchaseForEdit.id}`}>
                          <Package className="mr-2 h-4 w-4" />
                          Open Stock Inward to Add/Edit Items
                        </Link>
                      </Button>
                    </div>
                  </div>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    <p>Select a purchase from the "All Purchases" tab to edit stock inward items.</p>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        <PartySearchModal
          open={showPartySearch}
          parties={parties}
          isLoading={partiesLoading}
          onSelect={(party) => {
            setSelectedPartyId(party.id);
            form.setValue("partyId", party.id);
            form.setValue("partyName", party.name);
            form.setValue("city", party.city || "");
          }}
          onClose={() => setShowPartySearch(false)}
          title="Search & Select Supplier"
        />

      </div>
    </div>
  );
}

