import { useState, useEffect, useRef } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useKeyboardNavigation } from "@/hooks/useKeyboardNavigation";
import { SearchableSelect } from "@/components/searchable-select";
import { PartySearchModal } from "@/components/party-search-modal";
import { ItemSearchModal } from "@/components/item-search-modal";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { usePrintSettings } from "@/hooks/use-print-settings";
import { useAuth } from "@/hooks/useAuth";
import { Plus, Trash2, Save, Barcode, Search, FileText } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { useLocation } from "wouter";

interface Party {
  id: number;
  code: string;
  name: string;
  city: string | null;
}

interface Item {
  id: number;
  code: string;
  name: string;
  hsnCode: string | null;
  cost: string;
}

interface SaleLineItem {
  tempId: string;
  itemId: number | null;
  purchaseItemId: number | null;
  stockInwardId?: number | null;
  barcode: string;
  itemCode: string;
  itemName: string;
  hsnCode: string;
  quantity: number;
  rate: number;
  discount: number;
  discountPercent: number;
  amount: number;
}

export default function SalesEstimate() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const { shouldAutoPrint, shouldDirectPrint } = usePrintSettings();
  const { user } = useAuth();
  const canDeleteBill = user?.role === "admin" || user?.role === "superadmin";
  const barcodeInputRef = useRef<HTMLInputElement>(null);
  const dateInputRef = useRef<HTMLInputElement>(null);
  const formContainerRef = useRef<HTMLDivElement>(null);
  useKeyboardNavigation(formContainerRef);

  useEffect(() => {
    dateInputRef.current?.focus();
  }, []);

  const [selectedPartyId, setSelectedPartyId] = useState<number | null>(null);
  const [isWalkIn, setIsWalkIn] = useState(false);
  const [walkInName, setWalkInName] = useState("");
  const [lineItems, setLineItems] = useState<SaleLineItem[]>([]);
  const [invoiceDate, setInvoiceDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [barcodeInput, setBarcodeInput] = useState("");
  const [searchMode, setSearchMode] = useState<"item" | "barcode">("item");
  const [mobile, setMobile] = useState("");
  const [amountGiven, setAmountGiven] = useState(0);
  const [showPartySearch, setShowPartySearch] = useState(false);
  const [showItemSearch, setShowItemSearch] = useState(false);
  const [selectedLineItemTempId, setSelectedLineItemTempId] = useState<string | null>(null);

  const { data: parties, isLoading: partiesLoading } = useQuery<Party[]>({
    queryKey: ["/api/parties"],
  });

  const { data: items, isLoading: itemsLoading } = useQuery<Item[]>({
    queryKey: ["/api/items"],
  });

  const { data: stockInfo = {} } = useQuery<{ [key: number]: { itemId: number; availableQty: number; isBarcoded: boolean } }>({
    queryKey: ["/api/stock/info"],
  });

  const selectedParty = parties?.find((p) => p.id === selectedPartyId);

  const handleBarcodeSearch = async () => {
    if (!barcodeInput.trim()) return;

    try {
      const response = await apiRequest("GET", `/api/inventory/barcode/${encodeURIComponent(barcodeInput.trim())}`);
      const data: any = await response.json();

      // Check if item is already sold
      if (data.soldAt) {
        toast({
          title: "Item Already Sold",
          description: `${data.itemName} (${data.barcode}) has already been sold and cannot be scanned again`,
          variant: "destructive",
        });
        setBarcodeInput("");
        return;
      }

      const newItem: SaleLineItem = {
        tempId: Date.now().toString(),
        itemId: data.itemId,
        purchaseItemId: data.purchaseItemId,
        barcode: data.barcode || "",
        itemCode: "",
        itemName: data.itemName || "",
        hsnCode: data.hsnCode || "",
        quantity: 1,
        rate: parseFloat(data.mrp) || parseFloat(data.rrate) || 0,
        discount: 0,
        discountPercent: 0,
        amount: 0,
      };

      recalculateItem(newItem);
      setLineItems([...lineItems, newItem]);
      setBarcodeInput("");
      barcodeInputRef.current?.focus();

      toast({
        title: "Item Added",
        description: `${data.itemName} added`,
      });
    } catch (error) {
      toast({
        title: "Barcode Not Found",
        description: "No item found with this barcode",
        variant: "destructive",
      });
    }
  };

  const recalculateItem = (item: SaleLineItem) => {
    const qty = parseFloat(item.quantity.toString()) || 0;
    const rate = parseFloat(item.rate.toString()) || 0;
    const discountPercent = parseFloat(item.discountPercent.toString()) || 0;

    let amount = qty * rate;
    const discountAmount = amount * (discountPercent / 100);
    amount = amount - discountAmount;
    item.discount = discountAmount;
    item.amount = amount;
  };

  const addLineItem = () => {
    setLineItems([
      ...lineItems,
      {
        tempId: Date.now().toString(),
        itemId: null,
        purchaseItemId: null,
        barcode: "",
        itemCode: "",
        itemName: "",
        hsnCode: "",
        quantity: 1,
        rate: 0,
        discount: 0,
        discountPercent: 0,
        amount: 0,
      },
    ]);
  };

  const removeLineItem = (tempId: string) => {
    setLineItems(lineItems.filter((item) => item.tempId !== tempId));
  };

  const updateLineItem = (tempId: string, field: string, value: any) => {
    setLineItems(
      lineItems.map((item) => {
        if (item.tempId !== tempId) return item;

        const updated = { ...item, [field]: value };

        if (field === "itemId" && value && items) {
          const selectedItem = items.find((i) => i.id === parseInt(value));
          if (selectedItem) {
            updated.itemCode = selectedItem.code;
            updated.itemName = selectedItem.name;
            updated.hsnCode = selectedItem.hsnCode || "";
            updated.rate = parseFloat(selectedItem.cost);
          }
        }

        recalculateItem(updated);
        return updated;
      })
    );
  };

  const calculateTotals = () => {
    const totalQty = lineItems.reduce((sum, item) => sum + (parseFloat(item.quantity.toString()) || 0), 0);
    const discountTotal = lineItems.reduce((sum, item) => sum + item.discount, 0);
    const subTotal = lineItems.reduce((sum, item) => sum + item.amount, 0);
    const roundOff = Math.round(subTotal) - subTotal;
    const grandTotal = Math.round(subTotal);
    const amountReturn = amountGiven > 0 ? amountGiven - grandTotal : 0;

    return {
      totalQty,
      discountTotal,
      subTotal,
      roundOff,
      grandTotal,
      amountReturn,
    };
  };

  const totals = calculateTotals();

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (lineItems.length === 0) {
        throw new Error("Please add at least one item");
      }
      if (totals.grandTotal <= 0) {
        throw new Error("Total amount must be greater than zero");
      }

      const saleData = {
        billType: "EST",
        saleType: "ESTIMATE",
        paymentMode: "CASH",
        inclusiveTax: false,
        date: invoiceDate,
        partyId: isWalkIn ? null : selectedPartyId,
        partyName: isWalkIn ? (walkInName || "Walk-in Customer") : (selectedParty?.name || ""),
        partyCity: isWalkIn ? "" : (selectedParty?.city || ""),
        partyAddress: "",
        partyGstNo: "",
        gstType: 0,
        saleValue: totals.subTotal,
        discountTotal: totals.discountTotal,
        taxValue: 0,
        cgstTotal: 0,
        sgstTotal: 0,
        roundOff: totals.roundOff,
        grandTotal: totals.grandTotal,
        totalQty: totals.totalQty,
        amountGiven,
        amountReturn: totals.amountReturn,
        byCash: totals.grandTotal,
        byCard: 0,
        printOutstanding: false,
        partyOutstanding: 0,
        mobile,
        items: lineItems.map((item) => ({
          itemId: item.itemId,
          purchaseItemId: item.purchaseItemId,
          stockInwardId: item.stockInwardId,
          barcode: item.barcode,
          itemCode: item.itemCode,
          itemName: item.itemName,
          hsnCode: item.hsnCode,
          quantity: item.quantity,
          rate: item.rate,
          mrp: 0,
          discount: item.discount,
          discountPercent: item.discountPercent,
          amount: item.amount,
          saleValue: item.amount,
          taxValue: 0,
          tax: 0,
          cgst: 0,
          sgst: 0,
          cgstRate: 0,
          sgstRate: 0,
        })),
      };

      const response = await apiRequest("POST", "/api/sales", saleData);
      return response.json();
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/sales"] });
      queryClient.invalidateQueries({ queryKey: ["/api/dashboard/metrics"] });

      toast({
        title: "Success",
        description: "Estimate saved successfully",
      });

      // If direct print enabled, use silent print mode (tab closes after printing)
      // Otherwise use auto-print mode if enabled
      const printParam = shouldDirectPrint("EST") ? "?silent-print=true" : shouldAutoPrint("EST") ? "?print=auto" : "";
      window.open(`/invoice/${data.id}${printParam}`, '_blank');

      setLineItems([]);
      setSelectedPartyId(null);
      setIsWalkIn(false);
      setWalkInName("");
      setAmountGiven(0);
      setMobile("");
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  return (
    <div ref={formContainerRef} className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Estimate / Quotation</h1>
          <p className="text-muted-foreground mt-2">
            Create estimate without GST (cash only)
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            onClick={() => saveMutation.mutate()}
            disabled={saveMutation.isPending || lineItems.length === 0 || totals.grandTotal <= 0}
            data-testid="button-save-estimate"
          >
            <Save className="mr-2 h-4 w-4" />
            {saveMutation.isPending ? "Saving..." : "Save & Print"}
          </Button>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>Estimate Details</CardTitle>
              <Badge variant="outline">
                <FileText className="mr-1 h-3 w-3" />
                No Tax
              </Badge>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="invoiceDate">Date</Label>
                <Input
                  id="invoiceDate"
                  type="date"
                  value={invoiceDate}
                  onChange={(e) => setInvoiceDate(e.target.value)}
                  data-testid="input-invoice-date"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="party">Customer</Label>
                <div className="flex gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    className="flex-1 justify-start text-left h-9"
                    onClick={() => setShowPartySearch(true)}
                    data-testid="button-search-party"
                  >
                    {selectedParty ? (
                      <div className="flex flex-col items-start">
                        <span className="font-medium text-sm">{selectedParty.code}</span>
                        <span className="text-xs text-muted-foreground">{selectedParty.name}</span>
                      </div>
                    ) : (
                      <span className="text-muted-foreground">Click to search customer...</span>
                    )}
                  </Button>
                  {selectedParty && (
                    <Button
                      type="button"
                      size="sm"
                      variant="ghost"
                      onClick={() => setSelectedPartyId(null)}
                      data-testid="button-clear-party"
                    >
                      Clear
                    </Button>
                  )}
                </div>
                <div className="flex gap-2 mt-2">
                  <Button
                    type="button"
                    size="sm"
                    variant={isWalkIn ? "default" : "outline"}
                    onClick={() => {
                      setIsWalkIn(true);
                      setSelectedPartyId(null);
                    }}
                    data-testid="button-walkin"
                  >
                    Walk-in
                  </Button>
                </div>
              </div>
            </div>
            {isWalkIn && (
              <div className="grid gap-4 sm:grid-cols-2">
                <div className="space-y-2">
                  <Label htmlFor="walkInName">Customer Name (Optional)</Label>
                  <Input
                    id="walkInName"
                    placeholder="Enter customer name"
                    value={walkInName}
                    onChange={(e) => setWalkInName(e.target.value)}
                    data-testid="input-walkin-name"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="mobile">Mobile (Optional)</Label>
                  <Input
                    id="mobile"
                    type="tel"
                    placeholder="Enter mobile number"
                    value={mobile}
                    onChange={(e) => setMobile(e.target.value)}
                    data-testid="input-mobile"
                  />
                </div>
              </div>
            )}

            <div className="flex items-center gap-2 p-3 border rounded-md">
              <div className="flex gap-2">
                <Button
                  size="sm"
                  variant={searchMode === "item" ? "default" : "outline"}
                  onClick={() => setSearchMode("item")}
                  data-testid="button-search-mode-item"
                >
                  <Search className="mr-1 h-3 w-3" />
                  Item Search
                </Button>
                <Button
                  size="sm"
                  variant={searchMode === "barcode" ? "default" : "outline"}
                  onClick={() => {
                    setSearchMode("barcode");
                    setTimeout(() => barcodeInputRef.current?.focus(), 100);
                  }}
                  data-testid="button-search-mode-barcode"
                >
                  <Barcode className="mr-1 h-3 w-3" />
                  Barcode Scan
                </Button>
              </div>
              {searchMode === "barcode" && (
                <div className="flex-1 flex gap-2">
                  <Input
                    ref={barcodeInputRef}
                    placeholder="Scan barcode..."
                    value={barcodeInput}
                    onChange={(e) => setBarcodeInput(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleBarcodeSearch()}
                    className="flex-1"
                    data-testid="input-barcode"
                  />
                  <Button onClick={handleBarcodeSearch} data-testid="button-barcode-add">
                    Add
                  </Button>
                </div>
              )}
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label>Items ({lineItems.length})</Label>
                {searchMode === "item" && (
                  <Button 
                    size="sm" 
                    onClick={() => {
                      const newLineItem: SaleLineItem = {
                        tempId: Date.now().toString(),
                        itemId: null,
                        purchaseItemId: null,
                        barcode: "",
                        itemCode: "",
                        itemName: "",
                        hsnCode: "",
                        quantity: 1,
                        rate: 0,
                        discount: 0,
                        discountPercent: 0,
                        amount: 0,
                      };
                      setLineItems([...lineItems, newLineItem]);
                      setSelectedLineItemTempId(newLineItem.tempId);
                      setShowItemSearch(true);
                    }}
                    data-testid="button-add-line-item"
                  >
                    <Plus className="mr-1 h-3 w-3" />
                    Add Item
                  </Button>
                )}
              </div>

              <div className="border rounded-md overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[250px]">Item</TableHead>
                      <TableHead className="w-[80px]">Qty</TableHead>
                      <TableHead className="w-[100px]">Rate</TableHead>
                      <TableHead className="w-[80px]">Disc%</TableHead>
                      <TableHead className="w-[100px] text-right">Amount</TableHead>
                      <TableHead className="w-[50px]"></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {lineItems.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                          Add items to create estimate
                        </TableCell>
                      </TableRow>
                    ) : (
                      lineItems.map((item) => (
                        <TableRow key={item.tempId}>
                          <TableCell>
                            {item.barcode ? (
                              <div>
                                <div className="font-medium">{item.itemName}</div>
                                <div className="text-xs text-muted-foreground">BC: {item.barcode}</div>
                              </div>
                            ) : (
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                className="w-full justify-start text-left h-8"
                                onClick={() => {
                                  setSelectedLineItemTempId(item.tempId);
                                  setShowItemSearch(true);
                                }}
                                data-testid={`button-select-item-${item.tempId}`}
                              >
                                {item.itemName ? (
                                  <span className="text-sm">{item.itemName}</span>
                                ) : (
                                  <span className="text-muted-foreground text-sm">Click to search item...</span>
                                )}
                              </Button>
                            )}
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0"
                              step="0.001"
                              value={item.quantity}
                              onChange={(e) => updateLineItem(item.tempId, "quantity", parseFloat(e.target.value) || 0)}
                              className="w-16"
                              data-testid={`input-qty-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0"
                              step="0.01"
                              value={item.rate}
                              onChange={(e) => updateLineItem(item.tempId, "rate", parseFloat(e.target.value) || 0)}
                              className="w-20"
                              data-testid={`input-rate-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0"
                              max="100"
                              step="0.01"
                              value={item.discountPercent}
                              onChange={(e) => updateLineItem(item.tempId, "discountPercent", parseFloat(e.target.value) || 0)}
                              className="w-16"
                              data-testid={`input-discount-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell className="text-right font-medium">
                            ₹{item.amount.toFixed(2)}
                          </TableCell>
                          <TableCell>
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </div>
            </div>
          </CardContent>
        </Card>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Payment (Cash Only)</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-3">
                <div className="flex justify-between text-sm">
                  <span>Total Qty:</span>
                  <span>{totals.totalQty.toFixed(3)}</span>
                </div>
                {totals.discountTotal > 0 && (
                  <div className="flex justify-between text-sm text-green-600">
                    <span>Discount:</span>
                    <span>-₹{totals.discountTotal.toFixed(2)}</span>
                  </div>
                )}
                <div className="flex justify-between text-sm">
                  <span>Round Off:</span>
                  <span>₹{totals.roundOff.toFixed(2)}</span>
                </div>
                <div className="border-t pt-3">
                  <div className="flex justify-between text-xl font-bold">
                    <span>Total:</span>
                    <span>₹{totals.grandTotal}</span>
                  </div>
                </div>
              </div>

              <div className="space-y-3 border-t pt-4">
                <div className="space-y-2">
                  <Label htmlFor="amount-given">Amount Received</Label>
                  <Input
                    id="amount-given"
                    type="number"
                    min="0"
                    step="1"
                    value={amountGiven || ""}
                    onChange={(e) => setAmountGiven(parseFloat(e.target.value) || 0)}
                    placeholder="Enter amount"
                    data-testid="input-amount-given"
                  />
                </div>
                {amountGiven >= totals.grandTotal && totals.grandTotal > 0 && (
                  <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-lg border border-green-200 dark:border-green-800">
                    <div className="flex justify-between items-center">
                      <span className="text-green-700 dark:text-green-300">Return:</span>
                      <span className="text-2xl font-bold text-green-600 dark:text-green-400">
                        ₹{totals.amountReturn.toFixed(0)}
                      </span>
                    </div>
                  </div>
                )}
              </div>

              <div className="space-y-2">
                <Label htmlFor="mobile">Mobile (Optional)</Label>
                <Input
                  id="mobile"
                  type="tel"
                  value={mobile}
                  onChange={(e) => setMobile(e.target.value)}
                  placeholder="Customer mobile"
                  data-testid="input-mobile"
                />
              </div>
            </CardContent>
          </Card>

          {selectedParty && (
            <Card>
              <CardHeader>
                <CardTitle className="text-sm">Customer</CardTitle>
              </CardHeader>
              <CardContent className="text-sm">
                <p className="font-medium">{selectedParty.name}</p>
                <p className="text-muted-foreground">{selectedParty.city}</p>
              </CardContent>
            </Card>
          )}
        </div>
      </div>

      <PartySearchModal
        open={showPartySearch}
        parties={parties}
        isLoading={partiesLoading}
        onSelect={(party) => {
          setSelectedPartyId(party.id);
          setIsWalkIn(false);
        }}
        onClose={() => setShowPartySearch(false)}
        title="Search & Select Customer"
      />

      <ItemSearchModal
        open={showItemSearch}
        items={items}
        isLoading={itemsLoading}
        onSelect={(item) => {
          if (selectedLineItemTempId) {
            updateLineItem(selectedLineItemTempId, "itemId", item.id);
            setSelectedLineItemTempId(null);
          }
          setShowItemSearch(false);
        }}
        onClose={() => {
          setShowItemSearch(false);
          setSelectedLineItemTempId(null);
        }}
        title="Search & Select Item"
      />
    </div>
  );
}

client/src/pages/credit-note.tsx.content:
import { useState, useEffect, useRef } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useKeyboardNavigation } from "@/hooks/useKeyboardNavigation";
import { PartySearchModal } from "@/components/party-search-modal";
import { ItemSearchModal } from "@/components/item-search-modal";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { usePrintSettings } from "@/hooks/use-print-settings";
import { Plus, Trash2, Save, Barcode, Search, Printer, AlertCircle, CreditCard } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { format } from "date-fns";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";

interface Party {
  id: number;
  code: string;
  name: string;
  shortname: string | null;
  address: string | null;
  city: string | null;
  state: string | null;
  stateCode: string | null;
  gstNo: string | null;
}

interface Item {
  id: number;
  code: string;
  name: string;
  hsnCode: string | null;
  cost: string;
  tax: string;
  cgst: string;
  sgst: string;
  packType: string;
}

interface CreditNoteLineItem {
  tempId: string;
  itemId: number | null;
  purchaseItemId: number | null;
  stockInwardId?: number | null;
  barcode: string;
  itemCode: string;
  itemName: string;
  hsnCode: string;
  quantity: number;
  rate: number;
  mrp: number;
  discount: number;
  discountPercent: number;
  amount: number;
  taxRate: number;
  cgstRate: number;
  sgstRate: number;
  saleValue: number;
  taxValue: number;
  cgst: number;
  sgst: number;
  stockQty: number | null;
}

export default function CreditNote() {
  const { toast } = useToast();
  const { shouldAutoPrint, shouldDirectPrint } = usePrintSettings();
  const barcodeInputRef = useRef<HTMLInputElement>(null);
  const formContainerRef = useRef<HTMLDivElement>(null);
  useKeyboardNavigation(formContainerRef);

  const [selectedPartyId, setSelectedPartyId] = useState<number | null>(null);
  const [gstType, setGstType] = useState<0 | 1>(0);
  const [inclusiveTax, setInclusiveTax] = useState(false);
  const [lineItems, setLineItems] = useState<CreditNoteLineItem[]>([]);
  const [invoiceDate, setInvoiceDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [barcodeInput, setBarcodeInput] = useState("");
  const [searchMode, setSearchMode] = useState<"item" | "barcode">("item");
  const [paymentMode, setPaymentMode] = useState<"CASH" | "CARD">("CASH");
  const [amountGiven, setAmountGiven] = useState<number>(0);
  const [partyOutstanding, setPartyOutstanding] = useState<number>(0);
  const [originalInvoiceNo, setOriginalInvoiceNo] = useState<string>("");
  const [reason, setReason] = useState<string>("");
  const [showPartySearch, setShowPartySearch] = useState(false);
  const [showItemSearch, setShowItemSearch] = useState(false);
  const [selectedLineItemTempId, setSelectedLineItemTempId] = useState<string | null>(null);

  const { data: parties, isLoading: partiesLoading } = useQuery<Party[]>({
    queryKey: ["/api/parties"],
  });

  const { data: items, isLoading: itemsLoading } = useQuery<Item[]>({
    queryKey: ["/api/items"],
  });

  const { data: stock } = useQuery<any[]>({
    queryKey: ["/api/stock"],
  });

  const { data: stockInfo = {} } = useQuery<{ [key: number]: { itemId: number; availableQty: number; isBarcoded: boolean } }>({
    queryKey: ["/api/stock/info"],
  });

  const selectedParty = parties?.find((p) => p.id === selectedPartyId);

  useEffect(() => {
    if (selectedPartyId) {
      apiRequest("GET", `/api/parties/${selectedPartyId}/outstanding`)
        .then((data: any) => setPartyOutstanding(data.outstanding || 0))
        .catch(() => setPartyOutstanding(0));
    } else {
      setPartyOutstanding(0);
    }
  }, [selectedPartyId]);

  const getStockQuantity = (itemId: number | null) => {
    if (!itemId || !stock) return null;
    const stockItem = stock.find((s) => s.itemId === itemId);
    return stockItem ? parseFloat(stockItem.quantity) : 0;
  };

  const handleBarcodeSearch = async () => {
    if (!barcodeInput.trim()) return;

    try {
      const response = await apiRequest("GET", `/api/inventory/barcode/${encodeURIComponent(barcodeInput.trim())}`);
      const data: any = await response.json();

      // For credit notes, allow already sold items (returns). No soldAt validation needed.
      // Unique barcode (qty=1): Can only scan once per bill
      if (data.stockQty === 1) {
        const alreadyAdded = lineItems.some(item => item.barcode === data.barcode || (item.itemId === data.itemId && item.quantity === 1));
        if (alreadyAdded) {
          toast({
            title: "Barcode Already Used",
            description: `${data.itemName} (${data.barcode}) has already been added to this bill`,
            variant: "destructive",
          });
          setBarcodeInput("");
          return;
        }
      }

      const newItem: CreditNoteLineItem = {
        tempId: Date.now().toString(),
        itemId: data.itemId,
        purchaseItemId: data.purchaseItemId,
        barcode: data.barcode || "",
        itemCode: "",
        itemName: data.itemName || "",
        hsnCode: data.hsnCode || "",
        quantity: 1,
        rate: inclusiveTax ? (parseFloat(data.rate) || parseFloat(data.mrp) || 0) : (parseFloat(data.rate) || parseFloat(data.mrp) || 0) / (1 + parseFloat(data.tax || "0") / 100),
        mrp: parseFloat(data.mrp) || 0,
        discount: 0,
        discountPercent: 0,
        amount: 0,
        taxRate: parseFloat(data.tax) || 0,
        cgstRate: parseFloat(data.cgst) || 0,
        sgstRate: parseFloat(data.sgst) || 0,
        saleValue: 0,
        taxValue: 0,
        cgst: 0,
        sgst: 0,
        stockQty: parseFloat(data.stockQty) || 0,
      };

      recalculateItem(newItem);
      setLineItems([...lineItems, newItem]);
      setBarcodeInput("");
      barcodeInputRef.current?.focus();

      toast({
        title: "Item Added",
        description: `${data.itemName} added from barcode scan`,
      });
    } catch (error) {
      toast({
        title: "Barcode Not Found",
        description: "No item found with this barcode in inventory",
        variant: "destructive",
      });
    }
  };

  const recalculateItem = (item: CreditNoteLineItem) => {
    const qty = parseFloat(item.quantity.toString()) || 0;
    const rate = parseFloat(item.rate.toString()) || 0;
    const discountPercent = parseFloat(item.discountPercent.toString()) || 0;
    const taxRate = item.taxRate || 0;

    let amount = qty * rate;
    const discount = amount * (discountPercent / 100);
    amount = amount - discount;
    item.discount = discount;

    let saleValue: number;
    let taxValue: number;

    if (inclusiveTax) {
      saleValue = amount / (1 + taxRate / 100);
      taxValue = amount - saleValue;
    } else {
      saleValue = amount;
      taxValue = saleValue * (taxRate / 100);
    }

    item.amount = inclusiveTax ? amount : saleValue;
    item.saleValue = saleValue;
    item.taxValue = taxValue;

    if (gstType === 0) {
      item.cgst = taxValue / 2;
      item.sgst = taxValue / 2;
    } else {
      item.cgst = taxValue;
      item.sgst = 0;
    }
  };

  const addLineItem = () => {
    const newItem: CreditNoteLineItem = {
      tempId: Date.now().toString(),
      itemId: null,
      purchaseItemId: null,
      barcode: "",
      itemCode: "",
      itemName: "",
      hsnCode: "",
      quantity: 1,
      rate: 0,
      mrp: 0,
      discount: 0,
      discountPercent: 0,
      amount: 0,
      taxRate: 0,
      cgstRate: 0,
      sgstRate: 0,
      saleValue: 0,
      taxValue: 0,
      cgst: 0,
      sgst: 0,
      stockQty: null,
    };
    setLineItems([...lineItems, newItem]);
  };

  const removeLineItem = (tempId: string) => {
    setLineItems(lineItems.filter((item) => item.tempId !== tempId));
  };

  const updateLineItem = (tempId: string, field: keyof CreditNoteLineItem, value: any) => {
    setLineItems(
      lineItems.map((item) => {
        if (item.tempId !== tempId) return item;

        const updated = { ...item };

        if (field === "itemId") {
          const selectedItem = items?.find((i) => i.id === parseInt(value));
          if (selectedItem) {
            updated.itemId = selectedItem.id;
            updated.itemCode = selectedItem.code;
            updated.itemName = selectedItem.name;
            updated.hsnCode = selectedItem.hsnCode || "";
            updated.rate = parseFloat(selectedItem.cost);
            updated.taxRate = parseFloat(selectedItem.tax);
            updated.cgstRate = parseFloat(selectedItem.cgst);
            updated.sgstRate = parseFloat(selectedItem.sgst);
            updated.stockQty = getStockQuantity(selectedItem.id);
          }
        } else if (field === "quantity" || field === "rate" || field === "discountPercent") {
          (updated as any)[field] = parseFloat(value) || 0;
        } else {
          (updated as any)[field] = value;
        }

        recalculateItem(updated);
        return updated;
      })
    );
  };

  useEffect(() => {
    setLineItems(
      lineItems.map((item) => {
        const updated = { ...item };
        recalculateItem(updated);
        return updated;
      })
    );
  }, [inclusiveTax, gstType]);

  const totals = lineItems.reduce(
    (acc, item) => ({
      quantity: acc.quantity + (parseFloat(item.quantity.toString()) || 0),
      saleValue: acc.saleValue + item.saleValue,
      discountTotal: acc.discountTotal + item.discount,
      taxValue: acc.taxValue + item.taxValue,
      cgstTotal: acc.cgstTotal + item.cgst,
      sgstTotal: acc.sgstTotal + item.sgst,
      grandTotal: acc.grandTotal + item.amount,
    }),
    { quantity: 0, saleValue: 0, discountTotal: 0, taxValue: 0, cgstTotal: 0, sgstTotal: 0, grandTotal: 0 }
  );

  const roundOff = Math.round(totals.grandTotal) - totals.grandTotal;
  const finalTotal = Math.round(totals.grandTotal);
  const amountReturn = amountGiven - finalTotal;

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (!selectedPartyId) {
        throw new Error("Please select a party/customer for credit note");
      }
      if (lineItems.length === 0) {
        throw new Error("Please add at least one item");
      }
      if (finalTotal <= 0) {
        throw new Error("Total amount must be greater than zero");
      }

      const creditNoteData = {
        billType: "CN",
        saleType: "CREDIT_NOTE",
        paymentMode,
        inclusiveTax,
        date: invoiceDate,
        partyId: selectedPartyId,
        partyName: selectedParty?.name || "",
        partyCity: selectedParty?.city || "",
        partyAddress: selectedParty?.address || "",
        partyGstNo: selectedParty?.gstNo || "",
        gstType,
        saleValue: totals.saleValue,
        discountTotal: totals.discountTotal,
        taxValue: totals.taxValue,
        cgstTotal: totals.cgstTotal,
        sgstTotal: totals.sgstTotal,
        roundOff,
        grandTotal: finalTotal,
        totalQty: totals.quantity,
        amountGiven,
        amountReturn: amountReturn > 0 ? amountReturn : 0,
        byCash: paymentMode === "CASH" ? finalTotal : 0,
        byCard: paymentMode === "CARD" ? finalTotal : 0,
        printOutstanding: false,
        partyOutstanding,
        originalInvoiceNo,
        reason,
        items: lineItems.map((item) => ({
          itemId: item.itemId,
          purchaseItemId: item.purchaseItemId,
          barcode: item.barcode,
          itemCode: item.itemCode,
          itemName: item.itemName,
          hsnCode: item.hsnCode,
          quantity: item.quantity,
          rate: item.rate,
          mrp: item.mrp,
          discount: item.discount,
          discountPercent: item.discountPercent,
          amount: item.amount,
          tax: item.taxRate,
          cgst: item.cgst,
          sgst: item.sgst,
        })),
      };

      return apiRequest("POST", "/api/sales", creditNoteData);
    },
    onSuccess: (data: any) => {
      queryClient.invalidateQueries({ queryKey: ["/api/sales"] });
      queryClient.invalidateQueries({ queryKey: ["/api/stock"] });
      queryClient.invalidateQueries({ queryKey: ["/api/parties", selectedPartyId, "outstanding"] });

      toast({
        title: "Success",
        description: "Credit Note saved successfully",
      });

      // If direct print enabled, use silent print mode (tab closes after printing)
      // Otherwise use auto-print mode if enabled
      const printParam = shouldDirectPrint("CN") ? "?silent-print=true" : shouldAutoPrint("CN") ? "?print=auto" : "";
      window.open(`/invoice/${data.id}${printParam}`, '_blank');

      setLineItems([]);
      setSelectedPartyId(null);
      setAmountGiven(0);
      setOriginalInvoiceNo("");
      setReason("");
      barcodeInputRef.current?.focus();
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  return (
    <div ref={formContainerRef} className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Credit Note (B2B)</h1>
          <p className="text-muted-foreground mt-2">
            Issue credit notes for returns and adjustments
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            onClick={() => saveMutation.mutate()}
            disabled={saveMutation.isPending || lineItems.length === 0 || !selectedPartyId || finalTotal <= 0}
            data-testid="button-save-credit-note"
          >
            <Save className="mr-2 h-4 w-4" />
            {saveMutation.isPending ? "Saving..." : "Save & Print"}
          </Button>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between flex-wrap gap-4">
              <CardTitle className="flex items-center gap-2">
                <CreditCard className="h-5 w-5" />
                Credit Note Details
              </CardTitle>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <Label htmlFor="inclusive-tax" className="text-sm">Tax Inclusive</Label>
                  <Switch
                    id="inclusive-tax"
                    checked={inclusiveTax}
                    onCheckedChange={setInclusiveTax}
                    data-testid="switch-inclusive-tax"
                  />
                </div>
              </div>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
              <div className="space-y-2">
                <Label htmlFor="invoiceDate">Date</Label>
                <Input
                  id="invoiceDate"
                  type="date"
                  value={invoiceDate}
                  onChange={(e) => setInvoiceDate(e.target.value)}
                  data-testid="input-invoice-date"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="party">Party/Customer *</Label>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="w-full justify-start h-9"
                  onClick={() => setShowPartySearch(true)}
                  data-testid="button-select-party"
                >
                  {selectedParty ? (
                    <span className="text-sm">{selectedParty.name} - {selectedParty.city}</span>
                  ) : (
                    <span className="text-muted-foreground text-sm">Click to search party...</span>
                  )}
                </Button>
              </div>
              <div className="space-y-2">
                <Label htmlFor="originalInvoice">Original Invoice No.</Label>
                <Input
                  id="originalInvoice"
                  placeholder="Original Bill No."
                  value={originalInvoiceNo}
                  onChange={(e) => setOriginalInvoiceNo(e.target.value)}
                  data-testid="input-original-invoice"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="reason">Reason</Label>
                <Input
                  id="reason"
                  placeholder="Return reason"
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  data-testid="input-reason"
                />
              </div>
            </div>

            {selectedParty && (
              <div className="p-3 border rounded-md bg-muted/50">
                <div className="flex items-center justify-between flex-wrap gap-2">
                  <div className="text-sm">
                    <span className="font-medium">{selectedParty.name}</span>
                    {selectedParty.city && <span className="text-muted-foreground"> - {selectedParty.city}</span>}
                    {selectedParty.gstNo && <span className="text-muted-foreground ml-2">(GST: {selectedParty.gstNo})</span>}
                  </div>
                  <Badge variant={partyOutstanding > 0 ? "destructive" : "secondary"}>
                    Outstanding: ₹{partyOutstanding.toFixed(2)}
                  </Badge>
                </div>
              </div>
            )}

            <div className="flex items-center gap-2 p-3 border rounded-md bg-muted/50">
              <div className="flex gap-2">
                <Button
                  size="sm"
                  variant={searchMode === "barcode" ? "default" : "outline"}
                  onClick={() => {
                    setSearchMode("barcode");
                    setTimeout(() => barcodeInputRef.current?.focus(), 100);
                  }}
                  data-testid="button-search-mode-barcode"
                >
                  <Barcode className="mr-1 h-3 w-3" />
                  Barcode Scan
                </Button>
                <Button
                  size="sm"
                  variant={searchMode === "item" ? "default" : "outline"}
                  onClick={() => setSearchMode("item")}
                  data-testid="button-search-mode-item"
                >
                  <Search className="mr-1 h-3 w-3" />
                  Item Search
                </Button>
              </div>
              {searchMode === "barcode" && (
                <div className="flex-1 flex gap-2">
                  <Input
                    ref={barcodeInputRef}
                    placeholder="Scan barcode..."
                    value={barcodeInput}
                    onChange={(e) => setBarcodeInput(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleBarcodeSearch()}
                    className="flex-1"
                    autoFocus
                    data-testid="input-barcode"
                  />
                  <Button onClick={handleBarcodeSearch} data-testid="button-barcode-add">
                    Add
                  </Button>
                </div>
              )}
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label>Return Items ({lineItems.length})</Label>
                {searchMode === "item" && (
                  <Button 
                    size="sm" 
                    onClick={() => {
                      const newItem: CreditNoteLineItem = {
                        tempId: Date.now().toString(),
                        itemId: null,
                        purchaseItemId: null,
                        barcode: "",
                        itemCode: "",
                        itemName: "",
                        hsnCode: "",
                        quantity: 1,
                        rate: 0,
                        mrp: 0,
                        discount: 0,
                        discountPercent: 0,
                        amount: 0,
                        taxRate: 0,
                        cgstRate: 0,
                        sgstRate: 0,
                        saleValue: 0,
                        taxValue: 0,
                        cgst: 0,
                        sgst: 0,
                        stockQty: null,
                      };
                      setLineItems([...lineItems, newItem]);
                      setSelectedLineItemTempId(newItem.tempId);
                      setShowItemSearch(true);
                    }}
                    data-testid="button-add-line-item"
                  >
                    <Plus className="mr-1 h-3 w-3" />
                    Add Item
                  </Button>
                )}
              </div>

              <div className="border rounded-md overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[200px]">Item</TableHead>
                      <TableHead className="w-[70px]">Stock</TableHead>
                      <TableHead className="w-[70px]">Qty</TableHead>
                      <TableHead className="w-[90px]">Rate</TableHead>
                      <TableHead className="w-[70px]">Disc%</TableHead>
                      <TableHead className="w-[100px] text-right">Amount</TableHead>
                      <TableHead className="w-[50px]"></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {lineItems.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={7} className="text-center text-muted-foreground py-8">
                          Add items to create credit note
                        </TableCell>
                      </TableRow>
                    ) : (
                      lineItems.map((item) => (
                        <TableRow key={item.tempId}>
                          <TableCell>
                            {item.barcode ? (
                              <div>
                                <div className="font-medium">{item.itemName}</div>
                                <div className="text-xs text-muted-foreground">BC: {item.barcode}</div>
                              </div>
                            ) : (
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                className="w-full justify-start text-left h-8"
                                onClick={() => {
                                  setSelectedLineItemTempId(item.tempId);
                                  setShowItemSearch(true);
                                }}
                                data-testid={`button-select-item-${item.tempId}`}
                              >
                                {item.itemName ? (
                                  <span className="text-sm">{item.itemName}</span>
                                ) : (
                                  <span className="text-muted-foreground text-sm">Click to search item...</span>
                                )}
                              </Button>
                            )}
                          </TableCell>
                          <TableCell>
                            {item.stockQty !== null && (
                              <Badge variant={item.stockQty < item.quantity ? "destructive" : "secondary"}>
                                {item.stockQty}
                              </Badge>
                            )}
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              min="0.01"
                              step="0.01"
                              value={item.quantity}
                              onChange={(e) => updateLineItem(item.tempId, "quantity", e.target.value)}
                              className="w-16"
                              data-testid={`input-qty-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              step="0.01"
                              min="0"
                              value={item.rate}
                              onChange={(e) => updateLineItem(item.tempId, "rate", e.target.value)}
                              className="w-20"
                              data-testid={`input-rate-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell>
                            <Input
                              type="number"
                              step="0.01"
                              min="0"
                              max="100"
                              value={item.discountPercent}
                              onChange={(e) => updateLineItem(item.tempId, "discountPercent", e.target.value)}
                              className="w-16"
                              data-testid={`input-disc-${item.tempId}`}
                            />
                          </TableCell>
                          <TableCell className="text-right font-medium">
                            ₹{item.amount.toFixed(2)}
                          </TableCell>
                          <TableCell>
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => removeLineItem(item.tempId)}
                              data-testid={`button-remove-${item.tempId}`}
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </div>
            </div>
          </CardContent>
        </Card>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Payment</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <RadioGroup
                value={paymentMode}
                onValueChange={(v) => setPaymentMode(v as "CASH" | "CARD")}
                className="flex gap-4"
              >
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="CASH" id="cash" data-testid="radio-cash" />
                  <Label htmlFor="cash">Cash</Label>
                </div>
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="CARD" id="card" data-testid="radio-card" />
                  <Label htmlFor="card">Card</Label>
                </div>
              </RadioGroup>

              {paymentMode === "CASH" && (
                <div className="space-y-3">
                  <div className="space-y-2">
                    <Label htmlFor="amountGiven">Amount to Return</Label>
                    <Input
                      id="amountGiven"
                      type="number"
                      value={amountGiven || ""}
                      onChange={(e) => setAmountGiven(parseFloat(e.target.value) || 0)}
                      placeholder="0.00"
                      data-testid="input-amount-given"
                    />
                  </div>
                  {amountGiven > 0 && amountGiven !== finalTotal && (
                    <Alert>
                      <AlertCircle className="h-4 w-4" />
                      <AlertDescription>
                        {amountGiven > finalTotal 
                          ? `Excess: ₹${(amountGiven - finalTotal).toFixed(2)}`
                          : `Pending: ₹${(finalTotal - amountGiven).toFixed(2)}`
                        }
                      </AlertDescription>
                    </Alert>
                  )}
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Credit Note Summary</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Items</span>
                  <span>{lineItems.length}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Total Qty</span>
                  <span>{totals.quantity.toFixed(2)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Return Value</span>
                  <span>₹{totals.saleValue.toFixed(2)}</span>
                </div>
                {totals.discountTotal > 0 && (
                  <div className="flex justify-between text-green-600">
                    <span>Discount</span>
                    <span>-₹{totals.discountTotal.toFixed(2)}</span>
                  </div>
                )}
                {gstType === 0 ? (
                  <>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">CGST</span>
                      <span>₹{totals.cgstTotal.toFixed(2)}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-muted-foreground">SGST</span>
                      <span>₹{totals.sgstTotal.toFixed(2)}</span>
                    </div>
                  </>
                ) : (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">IGST</span>
                    <span>₹{totals.taxValue.toFixed(2)}</span>
                  </div>
                )}
                {roundOff !== 0 && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Round Off</span>
                    <span>{roundOff > 0 ? "+" : ""}₹{roundOff.toFixed(2)}</span>
                  </div>
                )}
                <div className="border-t pt-2 mt-2">
                  <div className="flex justify-between font-bold text-lg">
                    <span>Credit Total</span>
                    <span>₹{finalTotal.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      <PartySearchModal
        open={showPartySearch}
        parties={parties}
        isLoading={partiesLoading}
        onSelect={(party) => {
          setSelectedPartyId(party.id);
          setShowPartySearch(false);
        }}
        onClose={() => setShowPartySearch(false)}
        title="Search & Select Customer"
      />

      <ItemSearchModal
        open={showItemSearch}
        items={items}
        isLoading={itemsLoading}
        onSelect={(item) => {
          if (selectedLineItemTempId) {
            updateLineItem(selectedLineItemTempId, "itemId", item.id);
            setSelectedLineItemTempId(null);
          }
          setShowItemSearch(false);
        }}
        onClose={() => {
          setShowItemSearch(false);
          setSelectedLineItemTempId(null);
        }}
        title="Search & Select Item"
      />
    </div>
  );
}

