import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { ItemSearchModal } from "@/components/item-search-modal";
import type { Item } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { Plus, Trash2, Save, Barcode, RefreshCw, Package, ArrowLeft, Check, Calculator, Layers, Hash } from "lucide-react";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { Link, useLocation, useSearch } from "wouter";
import { Separator } from "@/components/ui/separator";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";

const SIZE_CODES: { [key: string]: number } = {
  "F": 45, "S": 47, "M": 49, "L": 51, "XL": 53, "2L": 55, "3L": 57,
  "4L": 59, "5L": 61, "6L": 63, "7L": 65, "8L": 67, "OS": 69,
  "32": 32, "34": 34, "36": 36, "38": 38, "40": 40, "42": 42, "44": 44
};

const TAX_RATES = [0, 5, 12, 18, 28];

const purchaseItemSchema = z.object({
  itemId: z.number().nullable().optional(),
  itname: z.string().min(1, "Item name required"),
  brandname: z.string().optional(),
  sizeName: z.string().optional(),
  hsn: z.string().optional(),
  quality: z.string().optional(),
  dno1: z.string().optional(),
  pattern: z.string().optional(),
  sleeve: z.string().optional(),
  qty: z.number().min(1, "Quantity required"),
  cost: z.number().min(0, "Cost required"),
  tax: z.number().min(0).max(100),
  discountPercent: z.number().min(0).max(100).optional(),
  discountAmount: z.number().min(0).optional(),
  expensePercent: z.number().min(0).optional(),
  expenseAmount: z.number().min(0).optional(),
  profitPercent: z.number().min(0).optional(),
  mrpPercent: z.union([z.number().min(0), z.literal("")]).optional().transform(v => v === "" ? 0 : v ?? 0),
  mrp: z.number().min(0).optional(),
});

type PurchaseItemForm = z.infer<typeof purchaseItemSchema>;

interface Purchase {
  id: number;
  purchaseNo: number;
  date: string;
  invoiceNo: string | null;
  partyName: string | null;
  city: string | null;
  state: string | null;
  gstNo: string | null;
  phone: string | null;
  address: string | null;
  amount: string;
  beforeTaxAmount?: string;
  billTotalAmount?: string;
  totalQty: string;
  stockInwardCompleted: boolean;
}

interface PurchaseItem {
  id: number;
  purchaseId: number;
  serial: number;
  barcode: string | null;
  itemId: number | null;
  itname: string;
  brandname: string | null;
  name: string | null;
  quality: string | null;
  dno1: string | null;
  pattern: string | null;
  sleeve: string | null;
  qty: string;
  cost: string;
  tax: string;
  dis: string | null;      // Discount %
  rd: string | null;       // Discount amount (rate difference)
  addc: string | null;     // Additional cost % (expense)
  ncost: string | null;    // Net cost
  lcost: string | null;    // Landing cost
  prft: string | null;     // Profit %
  rrate: string | null;    // Selling rate
  mrp: string | null;      // MRP
  barcodeGenerated: boolean;
}

export default function StockInward() {
  const { toast } = useToast();
  const [, setLocation] = useLocation();
  const searchString = useSearch();
  const params = new URLSearchParams(searchString);
  const purchaseIdFromUrl = params.get('purchaseId');

  const [selectedPurchaseId, setSelectedPurchaseId] = useState<number | null>(
    purchaseIdFromUrl ? parseInt(purchaseIdFromUrl) : null
  );
  const [barcodePrefix, setBarcodePrefix] = useState("SKR");
  const [editingItemId, setEditingItemId] = useState<number | null>(null);
  const [showItemSearch, setShowItemSearch] = useState(false);
  const [selectedLineItemTempId, setSelectedLineItemTempId] = useState<string | null>(null);

  // Barcode generation mode dialog
  const [barcodeDialogOpen, setBarcodeDialogOpen] = useState(false);
  const [barcodeDialogItem, setBarcodeDialogItem] = useState<PurchaseItem | null>(null);
  const [barcodeMode, setBarcodeMode] = useState<"unique" | "bulk">("unique");

  // Mismatch confirmation dialog
  const [mismatchDialogOpen, setMismatchDialogOpen] = useState(false);
  const [mismatchError, setMismatchError] = useState<string>("");

  const { data: pendingPurchases } = useQuery<Purchase[]>({
    queryKey: ["/api/pending-purchases"],
  });

  const getCompanyHeader = (): Record<string, string> => {
    const companyId = localStorage.getItem("currentCompanyId");
    return companyId ? { "X-Company-Id": companyId } : {};
  };

  const { data: selectedPurchase, isLoading: purchaseLoading } = useQuery<Purchase>({
    queryKey: ["/api/purchases", selectedPurchaseId],
    queryFn: async () => {
      const res = await fetch(`/api/purchases/${selectedPurchaseId}`, {
        credentials: "include",
        headers: getCompanyHeader(),
      });
      if (!res.ok) throw new Error("Failed to fetch purchase");
      return res.json();
    },
    enabled: !!selectedPurchaseId,
  });

  const { data: purchaseItems, isLoading: purchaseItemsLoading, refetch: refetchItems } = useQuery<PurchaseItem[]>({
    queryKey: ["/api/purchases", selectedPurchaseId, "items"],
    queryFn: async () => {
      const res = await fetch(`/api/purchases/${selectedPurchaseId}/items`, {
        credentials: "include",
        headers: getCompanyHeader(),
      });
      if (!res.ok) throw new Error("Failed to fetch purchase items");
      return res.json();
    },
    enabled: !!selectedPurchaseId,
  });

  const { data: nextSerialData, refetch: refetchSerial } = useQuery({
    queryKey: ["/api/next-global-serial"],
    enabled: !!selectedPurchaseId,
  });

  const { data: masterItems } = useQuery<Item[]>({
    queryKey: ["/api/items"],
  });

  const form = useForm<PurchaseItemForm>({
    resolver: zodResolver(purchaseItemSchema),
    defaultValues: {
      itemId: null,
      itname: "",
      brandname: "",
      sizeName: "",
      hsn: "",
      quality: "",
      dno1: "",
      pattern: "",
      sleeve: "",
      qty: 1,
      cost: 0,
      tax: 0,
      discountPercent: 0,
      discountAmount: 0,
      expensePercent: 0,
      expenseAmount: 0,
      profitPercent: 10,
      mrpPercent: 0,
      mrp: 0,
    },
  });

  const handleItemSelect = (itemId: string) => {
    const item = (masterItems as any)?.find((i: any) => i.id.toString() === itemId);
    if (item) {
      form.setValue("itemId", item.id);
      form.setValue("itname", item.name || "");
      form.setValue("brandname", item.brand || "");
      form.setValue("hsn", item.hsn || "");
      if (item.mrp) {
        form.setValue("mrp", parseFloat(item.mrp));
      }
      if (item.tax) {
        form.setValue("tax", parseFloat(item.tax));
      }
    }
  };

  const watchCost = form.watch("cost");
  const watchQty = form.watch("qty");
  const watchTax = form.watch("tax");
  const watchDiscountPercent = form.watch("discountPercent");
  const watchExpensePercent = form.watch("expensePercent");
  const watchProfitPercent = form.watch("profitPercent");

  const calculateRates = (cost: number, tax: number, discountPercent: number = 0, expensePercent: number = 0, profitPercent: number = 10) => {
    const discountAmount = (cost * discountPercent) / 100;
    const netCost = cost - discountAmount;

    const expenseAmount = (netCost * expensePercent) / 100;
    const landingCost = netCost + expenseAmount;

    const taxAmount = (landingCost * tax) / 100;
    const costWithTax = landingCost + taxAmount;

    const profitAmount = (costWithTax * profitPercent) / 100;
    const rate = costWithTax + profitAmount;

    return {
      discountAmount: discountAmount.toFixed(2),
      netCost: netCost.toFixed(2),
      expenseAmount: expenseAmount.toFixed(2),
      landingCost: landingCost.toFixed(2),
      taxAmount: taxAmount.toFixed(2),
      profitAmount: profitAmount.toFixed(2),
      rate: rate.toFixed(2),
    };
  };

  const calculatedRates = calculateRates(
    watchCost || 0,
    watchTax || 0,
    watchDiscountPercent || 0,
    watchExpensePercent || 0,
    watchProfitPercent || 10
  );

  const generateBarcode = (serial: number, prefix: string = barcodePrefix): string => {
    const paddedSerial = serial.toString().padStart(7, '0');
    return `${prefix}${paddedSerial}`;
  };

  const addItemMutation = useMutation({
    mutationFn: async (data: any) => {
      return (await apiRequest("POST", "/api/purchase-items", data)).json();
    },
    onSuccess: () => {
      toast({ title: "Success", description: "Item added successfully" });
      refetchItems();
      refetchSerial();
      form.reset({
        itemId: null,
        itname: "",
        brandname: "",
        sizeName: "",
        hsn: "",
        quality: "",
        dno1: "",
        pattern: "",
        sleeve: "",
        qty: 1,
        cost: 0,
        tax: 0,
        discountPercent: 0,
        discountAmount: 0,
        expensePercent: 0,
        expenseAmount: 0,
        profitPercent: 10,
        mrp: 0,
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to add item",
        variant: "destructive",
      });
    },
  });

  const updateItemMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number; data: any }) => {
      return (await apiRequest("PUT", `/api/purchase-items/${id}`, data)).json();
    },
    onSuccess: () => {
      toast({ title: "Success", description: "Item updated successfully" });
      refetchItems();
      setEditingItemId(null);
      form.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update item",
        variant: "destructive",
      });
    },
  });

  const deleteItemMutation = useMutation({
    mutationFn: async (id: number) => {
      return apiRequest("DELETE", `/api/purchase-items/${id}`);
    },
    onSuccess: () => {
      toast({ title: "Success", description: "Item deleted successfully" });
      refetchItems();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete item",
        variant: "destructive",
      });
    },
  });

  // Generate UNIQUE barcodes (one per unit)
  const generateUniqueBarcodesMutation = useMutation({
    mutationFn: async ({ purchaseItemId, qty }: { purchaseItemId: number; qty: number }) => {
      const startSerial = (nextSerialData as any)?.serial || 1;
      const items = [];

      for (let i = 0; i < qty; i++) {
        const serial = startSerial + i;
        items.push({
          serial,
          barcode: generateBarcode(serial, barcodePrefix),
          status: "in_stock",
          qty: 1, // Each barcode has qty of 1
        });
      }

      return (await apiRequest("POST", `/api/purchase-items/${purchaseItemId}/generate-barcodes`, { items })).json();
    },
    onSuccess: (_, variables) => {
      toast({ title: "Success", description: `Generated ${variables.qty} unique barcodes (1 barcode per unit)` });
      refetchItems();
      refetchSerial();
      setBarcodeDialogOpen(false);
      setBarcodeDialogItem(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to generate barcodes",
        variant: "destructive",
      });
    },
  });

  // Generate BULK barcode (1 barcode for all qty)
  const generateBulkBarcodesMutation = useMutation({
    mutationFn: async ({ purchaseItemId, qty }: { purchaseItemId: number; qty: number }) => {
      const startSerial = (nextSerialData as any)?.serial || 1;
      const items = [
        {
          serial: startSerial,
          barcode: generateBarcode(startSerial, barcodePrefix),
          status: "in_stock",
          qty: qty, // Single barcode with full quantity
        }
      ];

      return (await apiRequest("POST", `/api/purchase-items/${purchaseItemId}/generate-barcodes`, { items })).json();
    },
    onSuccess: (_, variables) => {
      toast({ title: "Success", description: `Generated 1 bulk barcode for ${variables.qty} units` });
      refetchItems();
      refetchSerial();
      setBarcodeDialogOpen(false);
      setBarcodeDialogItem(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to generate barcode",
        variant: "destructive",
      });
    },
  });

  const completePurchaseMutation = useMutation({
    mutationFn: async (purchaseId: number) => {
      return (await apiRequest("POST", `/api/purchases/${purchaseId}/complete`)).json();
    },
    onSuccess: () => {
      toast({ title: "Success", description: "Purchase completed and stock updated" });
      queryClient.invalidateQueries({ queryKey: ["/api/purchases"] });
      queryClient.invalidateQueries({ queryKey: ["/api/pending-purchases"] });
      queryClient.invalidateQueries({ queryKey: ["/api/stock"] });
      setLocation("/purchase-entry");
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to complete purchase",
        variant: "destructive",
      });
    },
  });

  const handleAddItem = (data: PurchaseItemForm) => {
    if (!selectedPurchaseId) return;

    const rates = calculateRates(
      data.cost,
      data.tax,
      data.discountPercent || 0,
      data.expensePercent || 0,
      data.profitPercent || 10
    );

    // Calculate MRP from rate + MRP%
    const mrpPercent = data.mrpPercent || 0;
    const calculatedMrp = data.mrp && data.mrp > 0 
      ? data.mrp 
      : parseFloat(rates.rate) * (1 + mrpPercent / 100);

    const sizeCode = SIZE_CODES[data.sizeName?.toUpperCase() || ""] || 0;
    const nextSerial = (purchaseItems?.length || 0) + 1;

    // Map frontend fields to database schema fields
    const itemData = {
      purchaseId: selectedPurchaseId,
      serial: nextSerial,
      itemId: data.itemId || null,
      itname: data.itname,
      brandname: data.brandname || "",
      name: data.sizeName || "",
      quality: data.quality || "",
      dno1: data.dno1 || "",
      pattern: data.pattern || "",
      sleeve: data.sleeve || "",
      qty: data.qty.toString(),
      cost: data.cost.toString(),
      tax: data.tax.toString(),
      // Database field mappings:
      dis: (data.discountPercent || 0).toString(),  // Discount %
      rd: rates.discountAmount,                      // Rate difference (discount amount)
      addc: (data.expensePercent || 0).toString(),  // Additional cost %
      ncost: rates.netCost,                         // Net cost after discounts
      lcost: rates.landingCost,                     // Landing cost
      prft: (data.profitPercent || 10).toString(),  // Profit %
      rrate: rates.rate,                            // Retail rate (selling rate)
      mrp: calculatedMrp.toFixed(2),                // MRP
    };

    if (editingItemId) {
      updateItemMutation.mutate({ id: editingItemId, data: itemData });
    } else {
      addItemMutation.mutate(itemData);
    }
  };

  const handleEditItem = (item: PurchaseItem) => {
    setEditingItemId(item.id);
    // Map database fields back to form fields
    const rate = parseFloat(item.rrate || "0");
    const mrp = parseFloat(item.mrp || "0");
    const mrpPercent = rate > 0 ? ((mrp - rate) / rate) * 100 : 0;

    form.reset({
      itemId: item.itemId || null,
      itname: item.itname,
      brandname: item.brandname || "",
      sizeName: item.name || "",
      hsn: "",
      quality: item.quality || "",
      dno1: item.dno1 || "",
      pattern: item.pattern || "",
      sleeve: item.sleeve || "",
      qty: parseFloat(item.qty),
      cost: parseFloat(item.cost),
      tax: parseFloat(item.tax),
      discountPercent: parseFloat(item.dis || "0"),
      expensePercent: parseFloat(item.addc || "0"),
      profitPercent: parseFloat(item.prft || "10"),
      mrpPercent: mrpPercent > 0 ? mrpPercent : 0,
      mrp: mrp,
    });
  };

  const handleDeleteItem = (id: number) => {
    deleteItemMutation.mutate(id);
  };

  // Open barcode generation dialog
  const handleOpenBarcodeDialog = (item: PurchaseItem) => {
    setBarcodeDialogItem(item);
    setBarcodeMode("unique"); // Default to unique
    setBarcodeDialogOpen(true);
  };

  // Handle barcode generation based on selected mode
  const handleGenerateBarcodes = () => {
    if (!barcodeDialogItem) return;
    const qty = parseInt(barcodeDialogItem.qty);

    if (barcodeMode === "unique") {
      generateUniqueBarcodesMutation.mutate({ purchaseItemId: barcodeDialogItem.id, qty });
    } else {
      generateBulkBarcodesMutation.mutate({ purchaseItemId: barcodeDialogItem.id, qty });
    }
  };

  const handleCompletePurchase = () => {
    if (!selectedPurchaseId || !selectedPurchase || !purchaseItems) return;

    // Check barcodes first
    const allGenerated = purchaseItems?.every(item => item.barcodeGenerated);
    if (!allGenerated) {
      toast({
        title: "Warning",
        description: "Please generate barcodes for all items before completing",
        variant: "destructive",
      });
      return;
    }

    // Calculate total quantity from items
    const totalQtyAdded = purchaseItems.reduce((sum, item) => sum + parseFloat(item.qty || "0"), 0);
    const expectedQty = parseFloat(selectedPurchase.totalQty || "0");

    // Calculate total amount from items (qty * cost)
    const totalAmount = purchaseItems.reduce((sum, item) => {
      const itemCost = parseFloat(item.cost || "0");
      const itemQty = parseFloat(item.qty || "0");
      return sum + (itemCost * itemQty);
    }, 0);
    const expectedAmount = parseFloat(selectedPurchase.beforeTaxAmount || selectedPurchase.amount || "0");

    // Validation checks
    if (Math.abs(totalQtyAdded - expectedQty) > 0.01) {
      setMismatchError(`Quantity Mismatch: Total quantity added (${totalQtyAdded.toFixed(0)}) does not match expected quantity (${expectedQty.toFixed(0)}). Do you want to save anyway?`);
      setMismatchDialogOpen(true);
      return;
    }

    if (Math.abs(totalAmount - expectedAmount) > 0.01) {
      setMismatchError(`Amount Mismatch: Total amount (₹${totalAmount.toFixed(2)}) does not match expected amount (₹${expectedAmount.toFixed(2)}). Do you want to save anyway?`);
      setMismatchDialogOpen(true);
      return;
    }

    completePurchaseMutation.mutate(selectedPurchaseId!);
  };

  const handleSaveDespiteMismatch = () => {
    setMismatchDialogOpen(false);
    completePurchaseMutation.mutate(selectedPurchaseId!);
  };

  const totalQty = purchaseItems?.reduce((sum, item) => sum + parseFloat(item.qty || "0"), 0) || 0;
  const totalAmount = purchaseItems?.reduce((sum, item) => {
    const qty = parseFloat(item.qty || "0");
    const cost = parseFloat(item.cost || "0");
    return sum + (qty * cost);
  }, 0) || 0;
  const allBarcodesGenerated = purchaseItems?.every(item => item.barcodeGenerated) || false;

  if (!selectedPurchaseId) {
    return (
      <div className="h-full overflow-auto p-6">
        <div className="max-w-4xl mx-auto space-y-6">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" asChild data-testid="button-back">
              <Link href="/purchase-entry">
                <ArrowLeft className="h-4 w-4" />
              </Link>
            </Button>
            <div>
              <h1 className="text-3xl font-bold" data-testid="text-page-title">Stock Inward</h1>
              <p className="text-muted-foreground mt-1">Phase 2: Add items and generate barcodes</p>
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Select Purchase Entry</CardTitle>
            </CardHeader>
            <CardContent>
              {!pendingPurchases || pendingPurchases.length === 0 ? (
                <div className="text-center py-8">
                  <Package className="mx-auto h-12 w-12 text-muted-foreground mb-4" />
                  <p className="text-muted-foreground mb-4">No pending purchase entries found.</p>
                  <Button asChild data-testid="button-new-entry">
                    <Link href="/purchase-entry">Create New Purchase Entry</Link>
                  </Button>
                </div>
              ) : (
                <div className="space-y-4">
                  <p className="text-sm text-muted-foreground">
                    Select a pending purchase entry to add items and generate barcodes:
                  </p>
                  <div className="border rounded-md">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Entry No</TableHead>
                          <TableHead>Date</TableHead>
                          <TableHead>Invoice</TableHead>
