          <DialogFooter>
            <Button variant="outline" onClick={() => setMismatchDialogOpen(false)} data-testid="button-cancel-save">
              Cancel
            </Button>
            <Button onClick={handleSaveDespiteMismatch} data-testid="button-save-anyway">
              Save Anyway
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Item Search Modal */}
      <ItemSearchModal
        open={showItemSearch}
        items={masterItems || []}
        isLoading={false}
        onClose={() => setShowItemSearch(false)}
        onSelect={(item: Item) => {
          form.setValue("itemId", item.id);
          form.setValue("itname", item.name);
          form.setValue("hsn", item.hsnCode || "");
          setShowItemSearch(false);
        }}
      />
    </div>
  );
}

