    mrp: "699.00",
    brand: "ABC Brand",
    quality: "Premium",
    cost: "350.00",
    ncost: "340.00",
    lcost: "345.00",
    tax: "12",
    dno1: "DN-001",
    pattern: "Striped",
    sleeve: "Half",
    sizeCode: "49",
    serial: "001",
    status: "Active",
  };

  const [elements, setElements] = useState<TemplateElement[]>(elementTemplates);
  const [selectedElement, setSelectedElement] = useState<string | null>("barcode");
  const [dragging, setDragging] = useState<{ id: string; offsetX: number; offsetY: number; canvasRect: DOMRect } | null>(null);

  const { data: templates, refetch: refetchTemplates } = useQuery({
    queryKey: ["/api/barcode-label-templates"],
    enabled: open,
  });

  const saveMutation = useMutation({
    mutationFn: async (data: any) => {
      return (await apiRequest("POST", "/api/barcode-label-templates", data)).json();
    },
    onSuccess: () => {
      toast({ title: "Success", description: "Template saved successfully" });
      refetchTemplates();
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to save template", variant: "destructive" });
    },
  });

  const handleMouseDown = (e: React.MouseEvent, elementId: string) => {
    e.preventDefault();
    setSelectedElement(elementId);
    const elementRect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setDragging({
      id: elementId,
      offsetX: e.clientX - elementRect.left,
      offsetY: e.clientY - elementRect.top,
      canvasRect: null as any,
    });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!dragging) return;
    const canvasContainer = e.currentTarget as HTMLElement;
    const canvasInner = canvasContainer.querySelector('[data-canvas-inner]') as HTMLElement;
    if (!canvasInner) return;

    const canvasRect = canvasInner.getBoundingClientRect();
    const newXPixels = e.clientX - canvasRect.left - dragging.offsetX;
    const newYPixels = e.clientY - canvasRect.top - dragging.offsetY;
    let newX = Math.max(0, Math.min(newXPixels / scale, labelWidth - 2));
    let newY = Math.max(0, Math.min(newYPixels / scale, labelHeight - 2));

    if (snapToGrid) {
      newX = Math.round(newX);
      newY = Math.round(newY);
    } else {
      newX = Math.round(newX * 10) / 10;
      newY = Math.round(newY * 10) / 10;
    }

    setElements(
      elements.map((el) =>
        el.id === dragging.id ? { ...el, x: newX, y: newY } : el
      )
    );
  };

  const handleMouseUp = () => {
    setDragging(null);
  };

  const updateElement = (id: string, updates: Partial<TemplateElement>) => {
    setElements(elements.map((el) => (el.id === id ? { ...el, ...updates } : el)));
  };

  const handleSaveTemplate = () => {
    const config = JSON.stringify({ elements });
    saveMutation.mutate({
      name: templateName,
      labelWidth,
      labelHeight,
      labelsPerRow,
      labelsPerColumn: 10,
      marginTop,
      marginLeft: 5,
      gapHorizontal,
      gapVertical,
      config,
      prnProgram: prnProgram || null,
      isDefault,
    });
  };

  const selectedElConfig = elements.find((el) => el.id === selectedElement);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-7xl max-h-[95vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Label Designer - Visual Template Editor</DialogTitle>
        </DialogHeader>

        <div className="grid grid-cols-5 gap-4">
          {/* Preview - Left Side */}
          <div className="border rounded-lg p-3 bg-white flex flex-col">
            <div className="font-semibold text-sm mb-3">Preview</div>
            <div className="flex-1 border-2 border-dashed border-gray-300 rounded p-2 bg-gray-50 relative" style={{ aspectRatio: `${labelWidth}/${labelHeight}` }}>
              {elements.filter(el => el.visible).map((el) => {
                let value = "";
                if (el.id === "barcode") value = sampleData.barcode;
                else if (el.id === "itemName") value = sampleData.itname;
                else if (el.id === "size") value = sampleData.size;
                else if (el.id === "rate") value = "₹ " + parseFloat(sampleData.rate).toFixed(el.decimals ?? 2);
                else if (el.id === "mrp") value = "₹ " + parseFloat(sampleData.mrp).toFixed(el.decimals ?? 2);
                else if (el.id === "brand") value = sampleData.brand;
                else if (el.id === "quality") value = sampleData.quality;
                else if (el.id === "cost") value = parseFloat(sampleData.cost).toFixed(2);
                else if (el.id === "ncost") value = parseFloat(sampleData.ncost).toFixed(el.decimals ?? 2);
                else if (el.id === "lcost") value = parseFloat(sampleData.lcost).toFixed(el.decimals ?? 2);
                else if (el.id === "tax") value = sampleData.tax + "%";
                else if (el.id === "dno1") value = sampleData.dno1;
                else if (el.id === "pattern") value = sampleData.pattern;
                else if (el.id === "sleeve") value = sampleData.sleeve;
                else if (el.id === "sizeCode") value = sampleData.sizeCode;
                else if (el.id === "serial") value = sampleData.serial;
                else if (el.id === "status") value = sampleData.status;

                const widthPercent = labelWidth > 0 ? (el.width || 20) / labelWidth * 100 : 100;
                const heightPercent = labelHeight > 0 ? (el.height || 5) / labelHeight * 100 : 100;
                const xPercent = labelWidth > 0 ? el.x / labelWidth * 100 : 0;
                const yPercent = labelHeight > 0 ? el.y / labelHeight * 100 : 0;

                return (
                  <div key={el.id} style={{
                    position: "absolute",
                    left: `${xPercent}%`,
                    top: `${yPercent}%`,
                    width: `${widthPercent}%`,
                    height: `${heightPercent}%`,
                    fontSize: `${Math.max(6, el.fontSize * 0.6)}px`,
                    fontFamily: el.fontFamily || "Arial",
                    overflow: "hidden",
                    whiteSpace: "nowrap",
                    border: "0.5px solid #ddd",
                  }}>
                    <span className="text-gray-700">{value}</span>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Canvas - Main Area */}
          <div className="col-span-3 border rounded-lg p-4 bg-gray-50">
            <div className="flex flex-col gap-2 mb-4">
              <Label>Template Name</Label>
              <Input value={templateName} onChange={(e) => setTemplateName(e.target.value)} placeholder="My Label Template" />
            </div>

            <div className="flex gap-4 mb-4">
              <div className="flex-1">
                <Label className="text-xs">Width (mm)</Label>
                <Input type="number" value={labelWidth} onChange={(e) => setLabelWidth(Math.max(1, parseInt(e.target.value) || 50))} />
              </div>
              <div className="flex-1">
                <Label className="text-xs">Height (mm)</Label>
                <Input type="number" value={labelHeight} onChange={(e) => setLabelHeight(Math.max(1, parseInt(e.target.value) || 25))} />
              </div>
            </div>

            <div className="grid grid-cols-4 gap-3 mb-4 p-3 bg-blue-50 rounded border border-blue-200">
              <div>
                <Label className="text-xs">Top Margin (mm)</Label>
                <Input type="number" value={marginTop} onChange={(e) => setMarginTop(Math.max(0, parseInt(e.target.value) || 10))} className="text-xs" />
              </div>
              <div>
                <Label className="text-xs">Bottom Margin (mm)</Label>
                <Input type="number" value={marginBottom} onChange={(e) => setMarginBottom(Math.max(0, parseInt(e.target.value) || 10))} className="text-xs" />
              </div>
              <div>
                <Label className="text-xs">Horizontal Gap (mm)</Label>
                <Input type="number" value={gapHorizontal} onChange={(e) => setGapHorizontal(Math.max(0, parseInt(e.target.value) || 2))} className="text-xs" />
              </div>
              <div>
                <Label className="text-xs">Vertical Gap (mm)</Label>
                <Input type="number" value={gapVertical} onChange={(e) => setGapVertical(Math.max(0, parseInt(e.target.value) || 2))} className="text-xs" />
              </div>
            </div>

            <div className="mb-4">
              <Label className="text-xs font-semibold mb-2 block">Labels Per Row</Label>
              <div className="flex gap-2">
                {[2, 3, 4].map((num) => (
                  <Button
                    key={num}
                    size="sm"
                    variant={labelsPerRow === num ? "default" : "outline"}
                    onClick={() => setLabelsPerRow(num)}
                    data-testid={`button-labels-per-row-${num}`}
                    className="flex-1"
                  >
                    {num} Across
                  </Button>
                ))}
              </div>
            </div>

            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-muted-foreground">Drag elements to position them on your label</p>
              <div className="flex items-center gap-2">
                <div className="flex items-center gap-1">
                  <Checkbox 
                    id="snapToGrid" 
                    checked={snapToGrid} 
                    onCheckedChange={(checked) => setSnapToGrid(checked as boolean)} 
                  />
                  <Label htmlFor="snapToGrid" className="text-xs">Snap to Grid</Label>
                </div>
                <div className="flex items-center gap-1 ml-3 border rounded px-2 py-1 bg-white">
                  <Button 
                    size="sm" 
                    variant="ghost" 
                    onClick={() => {
                      setDragging(null);
                      setZoomLevel(Math.max(50, zoomLevel - 25));
                    }}
                    disabled={zoomLevel <= 50}
                    data-testid="button-zoom-out"
                  >
                    <ZoomOut className="h-4 w-4" />
                  </Button>
                  <span className="text-xs font-mono w-10 text-center">{zoomLevel}%</span>
                  <Button 
                    size="sm" 
                    variant="ghost" 
                    onClick={() => {
                      setDragging(null);
                      setZoomLevel(Math.min(200, zoomLevel + 25));
                    }}
                    disabled={zoomLevel >= 200}
                    data-testid="button-zoom-in"
                  >
                    <ZoomIn className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            </div>

            {/* Canvas */}
            <div
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              className="border-2 border-dashed border-gray-400 relative bg-white cursor-move overflow-auto flex items-center justify-center"
              style={{
                minWidth: `${labelWidth * scale + 20}px`,
                minHeight: `${labelHeight * scale + 20}px`,
                maxHeight: "550px",
              }}
            >
              <div
                data-canvas-inner
                style={{
                  width: `${labelWidth * scale}px`,
                  height: `${labelHeight * scale}px`,
                  position: "relative",
                }}
              >
                {/* Grid background */}
                <div
                  className="absolute inset-0 opacity-10 pointer-events-none"
                  style={{
                    backgroundImage: `
                      linear-gradient(0deg, transparent 24%, rgba(0,0,0,.1) 25%, rgba(0,0,0,.1) 26%, transparent 27%, transparent 74%, rgba(0,0,0,.1) 75%, rgba(0,0,0,.1) 76%, transparent 77%, transparent),
                      linear-gradient(90deg, transparent 24%, rgba(0,0,0,.1) 25%, rgba(0,0,0,.1) 26%, transparent 27%, transparent 74%, rgba(0,0,0,.1) 75%, rgba(0,0,0,.1) 76%, transparent 77%, transparent)
                    `,
                    backgroundSize: `${5 * scale}px ${5 * scale}px`,
                  }}
                />

                {elements
                  .filter((el) => el.visible)
                  .map((el) => (
                    <div
                      key={el.id}
                      onMouseDown={(e) => handleMouseDown(e, el.id)}
                      className={`absolute cursor-grab active:cursor-grabbing border transition-all ${
                        selectedElement === el.id ? "border-2 border-blue-500 bg-blue-50 shadow-lg" : "border border-gray-300 bg-white hover:bg-gray-100"
                      }`}
                      style={{
                        left: `${el.x * scale}px`,
                        top: `${el.y * scale}px`,
                        width: el.width ? `${el.width * scale}px` : "auto",
                        height: el.height ? `${el.height * scale}px` : "auto",
                        padding: "4px 6px",
                        fontSize: `${el.fontSize * 1.2}px`,
                        fontFamily: el.fontFamily || "Arial",
                        minWidth: "50px",
                        minHeight: "20px",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                      }}
                    >
                      <span className="text-xs font-semibold text-gray-600 truncate">{el.label}</span>
                    </div>
                  ))}
              </div>
            </div>

            <div className="flex items-center space-x-2 mt-4">
              <Checkbox id="isDefault" checked={isDefault} onCheckedChange={(checked) => setIsDefault(checked as boolean)} />
              <Label htmlFor="isDefault" className="text-sm">
                Set as default template
              </Label>
            </div>
          </div>

          {/* Properties Panel - Right Side */}
          <div className="border rounded-lg p-4 bg-gray-50 max-h-[550px] flex flex-col">
            <div className="font-semibold text-sm mb-4">Elements</div>
            <ScrollArea className="flex-1 pr-4 mb-4">
              <div className="space-y-2">
                {elements.map((el) => (
                  <div
                    key={el.id}
                    onClick={() => setSelectedElement(el.id)}
                    className={`p-2 rounded cursor-pointer border transition-all ${
                      selectedElement === el.id ? "border-blue-500 bg-blue-100" : "border-gray-200 bg-white hover:bg-gray-100"
                    }`}
                  >
                    <div className="flex items-center justify-between gap-2">
                      <Checkbox
                        checked={el.visible}
                        onCheckedChange={(checked) => updateElement(el.id, { visible: checked as boolean })}
                        onClick={(e) => e.stopPropagation()}
                      />
                      <span className="text-xs font-medium flex-1">{el.label}</span>
                    </div>
                  </div>
                ))}
              </div>
            </ScrollArea>

            {selectedElConfig && (
              <div className="space-y-3 border-t pt-3">
                <div className="font-semibold text-sm">Properties</div>
                <div>
                  <Label className="text-xs">Position X (mm)</Label>
                  <Input
                    type="number"
                    step="0.5"
                    value={selectedElConfig.x}
                    onChange={(e) => updateElement(selectedElConfig.id, { x: parseFloat(e.target.value) || 0 })}
                    className="text-xs"
                  />
                </div>
                <div>
                  <Label className="text-xs">Position Y (mm)</Label>
                  <Input
                    type="number"
                    step="0.5"
                    value={selectedElConfig.y}
                    onChange={(e) => updateElement(selectedElConfig.id, { y: parseFloat(e.target.value) || 0 })}
                    className="text-xs"
                  />
                </div>
                <div>
                  <Label className="text-xs">Font Size</Label>
                  <Input
                    type="number"
                    value={selectedElConfig.fontSize}
                    onChange={(e) => updateElement(selectedElConfig.id, { fontSize: parseInt(e.target.value) || 8 })}
                    className="text-xs"
                  />
                </div>
                <div>
                  <Label className="text-xs">Font Family</Label>
                  <select
                    value={selectedElConfig.fontFamily || "Arial"}
                    onChange={(e) => updateElement(selectedElConfig.id, { fontFamily: e.target.value })}
                    className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                    data-testid="select-font-family"
                  >
                    <option value="Arial">Arial</option>
                    <option value="Helvetica">Helvetica</option>
                    <option value="Times New Roman">Times New Roman</option>
                    <option value="Courier New">Courier New</option>
                    <option value="Verdana">Verdana</option>
                    <option value="Georgia">Georgia</option>
                    <option value="Trebuchet MS">Trebuchet MS</option>
                    <option value="Monospace">Monospace</option>
                  </select>
                </div>
                {selectedElConfig.type === "barcode" && (
                  <div>
                    <Label className="text-xs">Barcode Type</Label>
                    <select
                      value={selectedElConfig.barcodeType || "CODE128"}
                      onChange={(e) => updateElement(selectedElConfig.id, { barcodeType: e.target.value })}
                      className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                      data-testid="select-barcode-type"
                    >
                      <option value="CODE128">CODE 128</option>
                      <option value="CODE39">CODE 39</option>
                      <option value="EAN13">EAN-13</option>
                      <option value="EAN8">EAN-8</option>
                      <option value="UPC">UPC-A</option>
                      <option value="QR">QR Code</option>
                      <option value="PDF417">PDF417</option>
                      <option value="DATAMATRIX">Data Matrix</option>
                    </select>
                  </div>
                )}
                {(selectedElConfig.id === "rate" || selectedElConfig.id === "mrp" || selectedElConfig.id === "cost") && (
                  <div>
                    <Label className="text-xs">Decimal Places</Label>
                    <Input
                      type="number"
                      min="0"
                      max="4"
                      value={selectedElConfig.decimals ?? 2}
                      onChange={(e) => updateElement(selectedElConfig.id, { decimals: parseInt(e.target.value) || 0 })}
                      className="text-xs"
                      data-testid="input-decimals"
                    />
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* PRN Program Editor */}
        <div className="border rounded-lg p-4 bg-gray-50">
          <div className="flex items-center justify-between mb-2">
            <Label className="font-semibold">PRN Program (EPL2/ZPL for Zebra Printers)</Label>
            <Button 
              variant="outline" 
              size="sm"
              onClick={() => setShowPrnEditor(!showPrnEditor)}
              data-testid="button-toggle-prn-editor"
            >
              {showPrnEditor ? "Hide" : "Show"} PRN Editor
            </Button>
          </div>
          {showPrnEditor && (
            <div className="space-y-2">
              <p className="text-xs text-muted-foreground">
                Enter your EPL2/ZPL program. Use placeholders: {"{barcode}"}, {"{itemName}"}, {"{mrp}"}, {"{sellingPrice}"}, {"{hsnCode}"}, {"{size}"}, {"{sizeCode}"}
              </p>
              <textarea
                className="w-full h-40 p-2 border rounded font-mono text-xs"
                placeholder={`Example EPL2 Program:
N
q400
Q200,24
B50,20,0,1,2,7,80,B,"{barcode}"
A50,110,0,2,1,1,N,"{itemName}"
A50,135,0,2,1,1,N,"MRP: {mrp}  Rate: {sellingPrice}"
A50,160,0,1,1,1,N,"HSN: {hsnCode}"
P1`}
                value={prnProgram}
                onChange={(e) => setPrnProgram(e.target.value)}
                data-testid="textarea-prn-program"
              />
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button onClick={handleSaveTemplate} disabled={saveMutation.isPending} data-testid="button-save-template">
            Save Template
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

interface PrintBarcodeDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  items: StockInwardItem[];
  selectedItems: Set<number>;
  onSelectionChange: (selected: Set<number>) => void;
}

interface TemplateData {
  id: number;
  name: string;
  labelWidth: number | string;
  labelHeight: number | string;
  config: string;
}

function PrintBarcodeDialog({ open, onOpenChange, items, selectedItems, onSelectionChange }: PrintBarcodeDialogProps) {
  const { toast } = useToast();
  const [selectedTemplateId, setSelectedTemplateId] = useState<number | null>(null);

  const { data: templates, isLoading: templatesLoading } = useQuery({
    queryKey: ["/api/barcode-label-templates"],
    enabled: open,
  });

  // Set default template on first load
  useEffect(() => {
    if (templates && templates.length > 0 && !selectedTemplateId) {
      const defaultTemplate = templates.find((t: any) => t.isDefault) || templates[0];
      setSelectedTemplateId(defaultTemplate.id);
    }
  }, [templates, selectedTemplateId]);

  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      onSelectionChange(new Set(items.map(item => item.id)));
    } else {
      onSelectionChange(new Set());
    }
  };

  const handleSelectItem = (itemId: number, checked: boolean) => {
    const newSelected = new Set(selectedItems);
    if (checked) {
      newSelected.add(itemId);
    } else {
      newSelected.delete(itemId);
    }
    onSelectionChange(newSelected);
  };

  const handlePrint = () => {
    if (selectedItems.size === 0) {
      toast({ title: "No items selected", description: "Please select at least one barcode to print", variant: "destructive" });
      return;
    }

    const selectedItemsList = items.filter(item => selectedItems.has(item.id));
    const selectedTemplate = templates?.find((t: any) => t.id === selectedTemplateId);

    if (!selectedTemplate) {
      toast({ title: "No template selected", description: "Please select a template to use", variant: "destructive" });
      return;
    }

    let printHtml = `
      <html>
        <head>
          <title>Barcode Labels</title>
          <style>
            @page { margin: 10mm; size: A4; }
            body { margin: 0; font-family: Arial, sans-serif; }
            .label { 
              display: inline-block; 
              width: ${selectedTemplate.labelWidth}mm; 
              height: ${selectedTemplate.labelHeight}mm; 
              border: 1px solid #ccc; 
              margin: 2mm; 
              page-break-inside: avoid;
              position: relative;
              overflow: hidden;
              font-size: 10px;
            }
            .element { position: absolute; }
          </style>
        </head>
        <body>
    `;

    const templateConfig = JSON.parse(selectedTemplate.config);

    selectedItemsList.forEach(item => {
      const qty = item.qty ? parseInt(item.qty.toString()) : 1;
      for (let i = 0; i < qty; i++) {
        printHtml += `<div class="label" style="position: relative; width: ${selectedTemplate.labelWidth}mm; height: ${selectedTemplate.labelHeight}mm;">`;

        templateConfig.elements.forEach((el: any) => {
          if (!el.visible) return;

          let value = "";
          if (el.id === "barcode") value = item.barcode;
          else if (el.id === "itemName") value = item.itname;
          else if (el.id === "size") value = item.size || "-";
          else if (el.id === "rate") {
            const decimals = el.decimals !== undefined ? el.decimals : 2;
            value = "₹ " + parseFloat(item.rate).toFixed(decimals);
          }
          else if (el.id === "mrp") {
            const decimals = el.decimals !== undefined ? el.decimals : 2;
            value = "₹ " + parseFloat(item.mrp).toFixed(decimals);
          }
          else if (el.id === "brand") value = item.brandname || "";
          else if (el.id === "quality") value = item.quality || "";
          else if (el.id === "cost") value = parseFloat(item.cost).toFixed(2);

          if (value) {
            const fontFamily = el.fontFamily || "Arial";
            printHtml += `
              <div class="element" style="
                position: absolute;
                left: ${el.x}mm;
                top: ${el.y}mm;
                font-size: ${el.fontSize}px;
                font-family: ${fontFamily};
                width: ${el.width || 20}mm;
                height: ${el.height || 5}mm;
                overflow: hidden;
                white-space: nowrap;
                word-wrap: break-word;
              ">${value}</div>
            `;
          }
        });

        printHtml += `</div>`;
      }
    });

    printHtml += `
        </body>
      </html>
    `;

    const printWindow = window.open('', '', 'width=800,height=600');
    if (printWindow) {
      printWindow.document.write(printHtml);
      printWindow.document.close();
      setTimeout(() => {
        printWindow.print();
        onOpenChange(false);
      }, 250);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Print Barcodes</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label className="font-semibold">Select Label Template</Label>
            <Select value={selectedTemplateId?.toString() || ""} onValueChange={(val) => setSelectedTemplateId(parseInt(val))}>
              <SelectTrigger data-testid="select-template">
                <SelectValue placeholder="Choose a template..." />
              </SelectTrigger>
              <SelectContent>
                {templates?.map((template: any) => (
                  <SelectItem key={template.id} value={template.id.toString()}>
                    {template.name} {template.isDefault ? "(Default)" : ""}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="flex items-center space-x-2 border-b pb-3">
            <Checkbox
              id="selectAll"
              checked={selectedItems.size === items.length && items.length > 0}
              onCheckedChange={handleSelectAll}
            />
            <Label htmlFor="selectAll" className="font-semibold">
              Select All ({selectedItems.size}/{items.length} selected)
            </Label>
          </div>

          <ScrollArea className="h-[400px] pr-4">
            <div className="space-y-2">
              {items.map(item => (
                <div key={item.id} className="flex items-center space-x-3 p-2 border rounded">
                  <Checkbox
                    checked={selectedItems.has(item.id)}
                    onCheckedChange={(checked) => handleSelectItem(item.id, checked as boolean)}
                  />
                  <div className="flex-1">
                    <div className="font-mono font-bold text-sm">{item.barcode}</div>
                    <div className="text-sm">{item.itname}</div>
                    <div className="text-xs text-muted-foreground flex gap-2">
                      {item.brandname && <span>{item.brandname}</span>}
                      {item.size && <span>Size: {item.size}</span>}
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="font-bold">₹{parseFloat(item.rate).toFixed(2)}</div>
                    <div className="text-xs text-muted-foreground">
                      Qty: {item.qty || 1} stickers
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </ScrollArea>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button onClick={handlePrint} disabled={selectedItems.size === 0} data-testid="button-print-selected">
            <Printer className="h-4 w-4 mr-2" />
            Print {selectedItems.size > 0 ? `(${selectedItems.size})` : ""} Labels
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

interface Item {
  id: number;
  code: string;
  name: string;
  hsnCode?: string;
  cgstRate?: string;
  sgstRate?: string;
  packType?: string;
}

interface BarcodeManagementPageProps {
  showItemSearch: boolean;
  setShowItemSearch: (show: boolean) => void;
  items: Item[];
}

