import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { Plus, Trash2, Save, ArrowLeft, Printer } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { format } from "date-fns";
import { useLocation, useParams, Link } from "wouter";
import { Skeleton } from "@/components/ui/skeleton";

interface Party {
  id: number;
  code: string;
  name: string;
  address: string | null;
  city: string | null;
  state: string | null;
  stateCode: string | null;
  gstNo: string | null;
}

interface Item {
  id: number;
  code: string;
  name: string;
  hsnCode: string | null;
  cost: string;
  tax: string;
  cgst: string;
  sgst: string;
}

interface SaleLineItem {
  tempId: string;
  itemId: number | null;
  itemCode: string;
  itemName: string;
  hsnCode: string;
  quantity: number;
  rate: number;
  amount: number;
  taxRate: number;
  cgstRate: number;
  sgstRate: number;
  saleValue: number;
  taxValue: number;
  cgst: number;
  sgst: number;
}

interface ExistingSaleItem {
  id: number;
  itemId: number | null;
  itemCode: string;
  itemName: string;
  hsnCode: string | null;
  quantity: string;
  rate: string;
  amount: string;
  tax: string | null;
  cgst: string | null;
  sgst: string | null;
}

interface ExistingSale {
  id: number;
  invoiceNo: number;
  billType: string;
  saleType: string | null;
  paymentMode: string | null;
  date: string;
  partyId: number | null;
  partyName: string | null;
  partyCity: string | null;
  partyAddress: string | null;
  partyGstNo: string | null;
  mobile: string | null;
  gstType: number;
  saleValue: string;
  discountTotal: string | null;
  taxValue: string | null;
  cgstTotal: string | null;
  sgstTotal: string | null;
  roundOff: string | null;
  grandTotal: string;
  totalQty: string;
  amountGiven: string | null;
  amountReturn: string | null;
  byCash: string | null;
  byCard: string | null;
}

export default function EditSale() {
  const params = useParams();
  const saleId = params.id;
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [billType, setBillType] = useState<"GST" | "EST">("GST");
  const [saleType, setSaleType] = useState<string>("B2C");
  const [selectedPartyId, setSelectedPartyId] = useState<number | null>(null);
  const [gstType, setGstType] = useState<0 | 1>(0);
  const [lineItems, setLineItems] = useState<SaleLineItem[]>([]);
  const [invoiceDate, setInvoiceDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [mobile, setMobile] = useState("");
  const [amountGiven, setAmountGiven] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState<"cash" | "card">("cash");
  const [isInitialized, setIsInitialized] = useState(false);

  const { data: existingSale, isLoading: saleLoading } = useQuery<ExistingSale>({
    queryKey: ["/api/sales", saleId],
  });

  const { data: existingItems, isLoading: itemsLoading } = useQuery<ExistingSaleItem[]>({
    queryKey: ["/api/sales", saleId, "items"],
  });

  const { data: parties } = useQuery<Party[]>({
    queryKey: ["/api/parties"],
  });

  const { data: items } = useQuery<Item[]>({
    queryKey: ["/api/items"],
  });

  const { data: stock } = useQuery<any[]>({
    queryKey: ["/api/stock"],
  });

  useEffect(() => {
    if (existingSale && existingItems && !isInitialized) {
      setBillType(existingSale.billType === "EST" ? "EST" : "GST");
      setSaleType(existingSale.saleType || "B2C");
      setSelectedPartyId(existingSale.partyId);
      setGstType(existingSale.gstType as 0 | 1);
      setInvoiceDate(existingSale.date);
      setMobile(existingSale.mobile || "");
      setAmountGiven(existingSale.amountGiven ? parseFloat(existingSale.amountGiven) : 0);
      setPaymentMethod(parseFloat(existingSale.byCard || "0") > 0 ? "card" : "cash");

      const mappedItems: SaleLineItem[] = existingItems.map((item, index) => ({
        tempId: `existing-${item.id}-${index}`,
        itemId: item.itemId,
        itemCode: item.itemCode,
        itemName: item.itemName,
        hsnCode: item.hsnCode || "",
        quantity: parseFloat(item.quantity),
        rate: parseFloat(item.rate),
        amount: parseFloat(item.amount),
        taxRate: item.tax ? parseFloat(item.tax) : 0,
        cgstRate: item.cgst ? parseFloat(item.cgst) / parseFloat(item.quantity) : 0,
        sgstRate: item.sgst ? parseFloat(item.sgst) / parseFloat(item.quantity) : 0,
        saleValue: parseFloat(item.amount) - (item.cgst ? parseFloat(item.cgst) : 0) - (item.sgst ? parseFloat(item.sgst) : 0),
        taxValue: (item.cgst ? parseFloat(item.cgst) : 0) + (item.sgst ? parseFloat(item.sgst) : 0),
        cgst: item.cgst ? parseFloat(item.cgst) : 0,
        sgst: item.sgst ? parseFloat(item.sgst) : 0,
      }));

      setLineItems(mappedItems);
      setIsInitialized(true);
    }
  }, [existingSale, existingItems, isInitialized]);

  const getStockQuantity = (itemId: number | null) => {
    if (!itemId || !stock) return null;
    const stockItem = stock.find((s) => s.itemId === itemId);
    return stockItem ? parseFloat(stockItem.quantity) : 0;
  };

  const selectedParty = parties?.find((p) => p.id === selectedPartyId);

  const addLineItem = () => {
    setLineItems([
      ...lineItems,
      {
        tempId: Date.now().toString(),
        itemId: null,
        itemCode: "",
        itemName: "",
        hsnCode: "",
        quantity: 1,
        rate: 0,
        amount: 0,
        taxRate: 0,
        cgstRate: 0,
        sgstRate: 0,
        saleValue: 0,
        taxValue: 0,
        cgst: 0,
        sgst: 0,
      },
    ]);
  };

  const removeLineItem = (tempId: string) => {
    setLineItems(lineItems.filter((item) => item.tempId !== tempId));
  };

  const updateLineItem = (tempId: string, field: string, value: any) => {
    setLineItems(
      lineItems.map((item) => {
        if (item.tempId !== tempId) return item;

        const updated = { ...item, [field]: value };

        if (field === "itemId" && value && items) {
          const selectedItem = items.find((i) => i.id === parseInt(value));
          if (selectedItem) {
            updated.itemCode = selectedItem.code;
            updated.itemName = selectedItem.name;
            updated.hsnCode = selectedItem.hsnCode || "";
            updated.rate = parseFloat(selectedItem.cost);
            updated.taxRate = parseFloat(selectedItem.tax);
            updated.cgstRate = parseFloat(selectedItem.cgst);
            updated.sgstRate = parseFloat(selectedItem.sgst);
          }
        }

        const qty = parseFloat(updated.quantity.toString()) || 0;
        const rate = parseFloat(updated.rate.toString()) || 0;
        const taxRate = parseFloat(updated.taxRate.toString()) || 0;

        const amount = qty * rate;
        const saleValue = billType === "GST" ? amount / (1 + taxRate / 100) : amount;
        const taxValue = billType === "GST" ? amount - saleValue : 0;

        if (billType === "GST") {
          if (gstType === 0) {
            updated.cgst = taxValue / 2;
            updated.sgst = taxValue / 2;
          } else {
            updated.cgst = taxValue;
            updated.sgst = 0;
          }
        } else {
          updated.cgst = 0;
          updated.sgst = 0;
        }

        updated.amount = amount;
        updated.saleValue = saleValue;
        updated.taxValue = taxValue;

        return updated;
      })
    );
  };

  const calculateTotals = () => {
    const totalQty = lineItems.reduce((sum, item) => sum + (parseFloat(item.quantity.toString()) || 0), 0);
    const saleValue = lineItems.reduce((sum, item) => sum + item.saleValue, 0);
    const taxValue = lineItems.reduce((sum, item) => sum + item.taxValue, 0);
    const cgstTotal = lineItems.reduce((sum, item) => sum + item.cgst, 0);
    const sgstTotal = lineItems.reduce((sum, item) => sum + item.sgst, 0);
    const subTotal = saleValue + taxValue;
    const roundOff = Math.round(subTotal) - subTotal;
    const grandTotal = Math.round(subTotal);
    const amountReturn = amountGiven - grandTotal;

    return {
      totalQty,
      saleValue,
      taxValue,
      cgstTotal,
      sgstTotal,
      subTotal,
      roundOff,
      grandTotal,
      amountReturn,
    };
  };

  const totals = calculateTotals();

  const updateMutation = useMutation({
    mutationFn: async () => {
      if (lineItems.length === 0) {
        throw new Error("Please add at least one item");
      }

      const saleData = {
        billType,
        saleType,
        date: invoiceDate,
        partyId: selectedPartyId,
        partyName: selectedParty?.name || existingSale?.partyName || "",
        partyCity: selectedParty?.city || existingSale?.partyCity || "",
        partyAddress: selectedParty?.address || existingSale?.partyAddress || "",
        partyGstNo: selectedParty?.gstNo || existingSale?.partyGstNo || "",
        gstType,
        saleValue: totals.saleValue,
        taxValue: totals.taxValue,
        cgstTotal: totals.cgstTotal,
        sgstTotal: totals.sgstTotal,
        roundOff: totals.roundOff,
        grandTotal: totals.grandTotal,
        totalQty: totals.totalQty,
        amountGiven: amountGiven,
        amountReturn: totals.amountReturn,
        byCash: paymentMethod === "cash" ? totals.grandTotal : 0,
        byCard: paymentMethod === "card" ? totals.grandTotal : 0,
        mobile,
        items: lineItems.map((item) => ({
          itemId: item.itemId,
          itemCode: item.itemCode,
          itemName: item.itemName,
          hsnCode: item.hsnCode,
          quantity: item.quantity,
          rate: item.rate,
          amount: item.amount,
          saleValue: item.saleValue,
          taxValue: item.taxValue,
          tax: item.taxRate,
          cgst: item.cgst,
          sgst: item.sgst,
          cgstRate: item.cgstRate,
          sgstRate: item.sgstRate,
        })),
      };

      return apiRequest("PUT", `/api/sales/${saleId}`, saleData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/sales"] });
      queryClient.invalidateQueries({ queryKey: ["/api/sales", saleId] });
      queryClient.invalidateQueries({ queryKey: ["/api/sales", saleId, "items"] });
      queryClient.invalidateQueries({ queryKey: ["/api/dashboard/metrics"] });
      toast({
        title: "Success",
        description: "Invoice updated successfully",
      });
      setLocation("/sales");
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const isLoading = saleLoading || itemsLoading;

  if (isLoading) {
    return (
      <div className="p-6 space-y-6">
        <Skeleton className="h-10 w-48" />
        <Skeleton className="h-[600px] w-full" />
      </div>
    );
  }

  if (!existingSale) {
    return (
      <div className="p-6">
        <Card>
          <CardContent className="py-8 text-center">
            <p className="text-muted-foreground">Invoice not found</p>
            <Button asChild className="mt-4">
              <Link href="/sales">Back to Sales</Link>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div className="flex items-center gap-4">
          <Button variant="outline" asChild>
            <Link href="/sales">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Back
            </Link>
          </Button>
          <div>
            <h1 className="text-3xl font-semibold tracking-tight">Edit Invoice</h1>
            <p className="text-muted-foreground mt-1">
              Editing {existingSale.saleType}-{existingSale.invoiceNo}
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => window.open(`/invoice/${saleId}`, '_blank')}
            data-testid="button-view-invoice"
          >
            <Printer className="mr-2 h-4 w-4" />
            View & Print
          </Button>
          <Button
            onClick={() => updateMutation.mutate()}
            disabled={updateMutation.isPending || lineItems.length === 0}
            data-testid="button-save-sale"
          >
            <Save className="mr-2 h-4 w-4" />
            {updateMutation.isPending ? "Saving..." : "Save Changes"}
          </Button>
        </div>
      </div>

      <div className="grid gap-6 lg:grid-cols-3">
        <Card className="lg:col-span-2">
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle>Invoice Details</CardTitle>
              <Badge variant={billType === "GST" ? "default" : "secondary"}>
                {billType === "GST" ? "Tax Invoice" : "Estimate"}
              </Badge>
            </div>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 sm:grid-cols-3">
              <div className="space-y-2">
                <Label htmlFor="invoiceDate">Invoice Date</Label>
                <Input
                  id="invoiceDate"
                  type="date"
                  value={invoiceDate}
                  onChange={(e) => setInvoiceDate(e.target.value)}
                  data-testid="input-invoice-date"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="saleType">Sale Type</Label>
                <Select value={saleType} onValueChange={setSaleType}>
                  <SelectTrigger id="saleType" data-testid="select-sale-type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="B2B">B2B (Credit)</SelectItem>
                    <SelectItem value="B2C">B2C (Cash/Retail)</SelectItem>
                    <SelectItem value="ESTIMATE">Estimate</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="party">Customer</Label>
                <Select
                  value={selectedPartyId?.toString() || ""}
                  onValueChange={(v) => setSelectedPartyId(v ? parseInt(v) : null)}
                >
                  <SelectTrigger id="party" data-testid="select-party">
                    <SelectValue placeholder="Select customer" />
                  </SelectTrigger>
                  <SelectContent>
                    {parties?.map((party) => (
                      <SelectItem key={party.id} value={party.id.toString()}>
                        {party.name} ({party.code})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid gap-4 sm:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="gstType">GST Type</Label>
                <Select
                  value={gstType.toString()}
                  onValueChange={(v) => setGstType(parseInt(v) as 0 | 1)}
                >
                  <SelectTrigger id="gstType" data-testid="select-gst-type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="0">Local (CGST + SGST)</SelectItem>
                    <SelectItem value="1">Inter-State (IGST)</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="mobile">Mobile (Optional)</Label>
                <Input
                  id="mobile"
                  value={mobile}
                  onChange={(e) => setMobile(e.target.value)}
                  placeholder="Customer mobile"
                  data-testid="input-mobile"
                />
              </div>
            </div>

            <div className="border rounded-lg overflow-hidden mt-4">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[200px]">Item</TableHead>
                    <TableHead className="w-[100px]">Qty</TableHead>
                    <TableHead className="w-[100px]">Rate</TableHead>
                    <TableHead className="w-[100px]">Amount</TableHead>
                    <TableHead className="w-[80px]">Tax</TableHead>
                    <TableHead className="w-[60px]"></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {lineItems.map((lineItem) => (
                    <TableRow key={lineItem.tempId}>
                      <TableCell>
                        <Select
                          value={lineItem.itemId?.toString() || ""}
                          onValueChange={(v) => updateLineItem(lineItem.tempId, "itemId", v)}
                        >
                          <SelectTrigger data-testid={`select-item-${lineItem.tempId}`}>
                            <SelectValue placeholder="Select item">
                              {lineItem.itemName || "Select item"}
                            </SelectValue>
                          </SelectTrigger>
                          <SelectContent>
                            {items?.map((item) => (
                              <SelectItem key={item.id} value={item.id.toString()}>
                                {item.name} ({item.code})
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        {lineItem.itemId && (
                          <span className="text-xs text-muted-foreground">
                            Stock: {getStockQuantity(lineItem.itemId)}
                          </span>
                        )}
                      </TableCell>
                      <TableCell>
                        <Input
                          type="number"
                          value={lineItem.quantity}
                          onChange={(e) => updateLineItem(lineItem.tempId, "quantity", parseFloat(e.target.value) || 0)}
                          className="w-20"
                          data-testid={`input-qty-${lineItem.tempId}`}
                        />
                      </TableCell>
                      <TableCell>
                        <Input
                          type="number"
                          value={lineItem.rate}
                          onChange={(e) => updateLineItem(lineItem.tempId, "rate", parseFloat(e.target.value) || 0)}
                          className="w-24"
                          data-testid={`input-rate-${lineItem.tempId}`}
                        />
                      </TableCell>
                      <TableCell className="font-mono">
                        ₹{lineItem.amount.toFixed(2)}
                      </TableCell>
                      <TableCell className="text-sm text-muted-foreground">
                        {lineItem.taxRate}%
                      </TableCell>
                      <TableCell>
                        <Button
                          size="icon"
                          variant="ghost"
                          onClick={() => removeLineItem(lineItem.tempId)}
                          data-testid={`button-remove-item-${lineItem.tempId}`}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>

            <Button variant="outline" onClick={addLineItem} className="w-full" data-testid="button-add-item">
              <Plus className="mr-2 h-4 w-4" />
              Add Item
            </Button>
          </CardContent>
        </Card>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle>Invoice Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Sale Value:</span>
                <span className="font-mono">₹{totals.saleValue.toFixed(2)}</span>
              </div>
              {billType === "GST" && (
                <>
                  {gstType === 0 ? (
                    <>
                      <div className="flex justify-between text-sm">
                        <span className="text-muted-foreground">CGST:</span>
                        <span className="font-mono">₹{totals.cgstTotal.toFixed(2)}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-muted-foreground">SGST:</span>
                        <span className="font-mono">₹{totals.sgstTotal.toFixed(2)}</span>
                      </div>
                    </>
                  ) : (
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">IGST:</span>
                      <span className="font-mono">₹{totals.taxValue.toFixed(2)}</span>
                    </div>
                  )}
                </>
              )}
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Round Off:</span>
                <span className="font-mono">₹{totals.roundOff.toFixed(2)}</span>
              </div>
              <div className="border-t pt-3">
                <div className="flex justify-between font-semibold">
                  <span>Grand Total:</span>
                  <span className="font-mono text-lg">₹{totals.grandTotal.toFixed(2)}</span>
                </div>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Total Qty:</span>
                <span className="font-mono">{totals.totalQty}</span>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Payment</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label>Payment Method</Label>
                <Select
                  value={paymentMethod}
                  onValueChange={(v) => setPaymentMethod(v as "cash" | "card")}
                >
                  <SelectTrigger data-testid="select-payment-method">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="cash">Cash</SelectItem>
                    <SelectItem value="card">Card</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="amountGiven">Amount Given</Label>
                <Input
                  id="amountGiven"
                  type="number"
                  value={amountGiven}
                  onChange={(e) => setAmountGiven(parseFloat(e.target.value) || 0)}
                  data-testid="input-amount-given"
                />
              </div>
              {totals.amountReturn > 0 && (
                <div className="flex justify-between text-sm p-2 bg-muted rounded">
                  <span>Return:</span>
                  <span className="font-mono font-medium">₹{totals.amountReturn.toFixed(2)}</span>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

client/src/components/InvoicePrint.tsx.content:
import { forwardRef } from "react";
import { format } from "date-fns";
import { numberToWords } from "@/lib/number-to-words";
import { translateToTamil } from "@/lib/tamil-translator";

interface InvoiceItem {
  id?: number;
  itemName: string;
  itemCode?: string;
  hsnCode?: string;
  barcode?: string;
  quantity: number;
  rate: number;
  discount?: number;
  discountPercent?: number;
  taxPercent?: number;
  cgst?: number;
  sgst?: number;
  igst?: number;
  amount: number;
}

interface InvoiceData {
  invoiceNo: string;
  date: string;
  partyName?: string;
  partyAddress?: string;
  partyCity?: string;
  partyState?: string;
  partyGstNo?: string;
  partyPhone?: string;
  items: InvoiceItem[];
  subtotal: number;
  totalDiscount: number;
  totalCgst: number;
  totalSgst: number;
  totalIgst: number;
  roundOff: number;
  grandTotal: number;
  cashGiven?: number;
  cashReturn?: number;
  previousBalance?: number;
  currentBalance?: number;
  isInterState?: boolean;
  totalTax?: number;
  gstType?: number;
  billType?: string;
  saleType?: string;
  irn?: string | null;
  ackNumber?: string | null;
  ackDate?: string | null;
  qrCode?: string | null;
}

interface BillTemplate {
  formatType: string;
  logoUrl?: string | null;
  headerText?: string | null;
  footerText?: string | null;
  showTaxBreakup: boolean;
  showHsnCode: boolean;
  showItemCode: boolean;
  showPartyBalance?: boolean;
  showBankDetails?: boolean;
  showCashReturn?: boolean;
  enableTamilPrint?: boolean;
  bankDetails?: string | null;
  termsAndConditions?: string | null;
  fontSize: number;
}

interface InvoicePrintProps {
  invoice: InvoiceData;
  template: BillTemplate;
  companyName?: string;
  companyAddress?: string;
  companyGst?: string;
  companyPhone?: string;
  companyState?: string;
  companyPincode?: string;
  enableTamilPrint?: boolean;
}

export const InvoiceA4Print = forwardRef<HTMLDivElement, InvoicePrintProps>(
  ({ invoice, template, companyName, companyAddress, companyGst, companyPhone, enableTamilPrint }, ref) => {
    const isB4 = template.formatType === "B4";
    const pageWidth = isB4 ? "250mm" : "210mm";
    const pageHeight = isB4 ? "353mm" : "297mm";

    return (
      <div
        ref={ref}
        className="bg-white text-black"
        style={{
          width: pageWidth,
          minHeight: pageHeight,
          padding: isB4 ? "15mm" : "10mm",
          fontSize: `${template.fontSize}px`,
          fontFamily: "Arial, sans-serif",
          boxSizing: "border-box",
        }}
      >
        <style>
          {`
            @media print {
              @page {
                size: ${isB4 ? "B4 portrait" : "A4 portrait"};
                margin: ${isB4 ? "10mm" : "8mm"};
              }
              body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
            }
          `}
        </style>

        <div className="flex justify-between items-start mb-4">
          <div className="flex-1">
            {template.logoUrl && (
              <img
                src={template.logoUrl}
                alt="Company Logo"
                style={{ maxHeight: "60px", marginBottom: "8px", objectFit: "contain" }}
              />
            )}
            {template.headerText ? (
              <div style={{ whiteSpace: "pre-line", fontWeight: 600, fontSize: "14px" }}>
                {template.headerText}
              </div>
            ) : (
              <>
                <div style={{ fontSize: "18px", fontWeight: 700 }}>{companyName}</div>
                {companyAddress && <div style={{ fontSize: "11px" }}>{companyAddress}</div>}
                {companyGst && <div style={{ fontSize: "11px" }}>GSTIN: {companyGst}</div>}
                {companyPhone && <div style={{ fontSize: "11px" }}>Phone: {companyPhone}</div>}
              </>
            )}
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: "20px", fontWeight: 700, marginBottom: "8px" }}>
              {invoice.billType === "CN" ? "CREDIT NOTE" : invoice.billType === "DN" ? "DEBIT NOTE" : invoice.billType === "EST" ? "ESTIMATE" : invoice.saleType === "PROFORMA" ? "PROFORMA INVOICE" : "TAX INVOICE"}
            </div>
            <div style={{ fontSize: "11px" }}>
              <div><span style={{ fontWeight: 500 }}>Invoice No:</span> {invoice.invoiceNo}</div>
              <div><span style={{ fontWeight: 500 }}>Date:</span> {format(new Date(invoice.date), "dd/MM/yyyy")}</div>
            </div>
          </div>
        </div>

        <div style={{ border: "1px solid black", padding: "10px", marginBottom: "10px" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "15px" }}>
            <div>
              <div style={{ fontWeight: 700, marginBottom: "4px", fontSize: "11px" }}>{translateToTamil("Bill To", enableTamilPrint)}:</div>
              <div style={{ fontWeight: 600, fontSize: "12px" }}>{invoice.partyName || "Cash Customer"}</div>
              {invoice.partyAddress && <div style={{ fontSize: "10px" }}>{invoice.partyAddress}</div>}
              {invoice.partyCity && <div style={{ fontSize: "10px" }}>{invoice.partyCity}{invoice.partyState ? `, ${invoice.partyState}` : ""}</div>}
              {invoice.partyGstNo && <div style={{ fontSize: "10px" }}>GSTIN: {invoice.partyGstNo}</div>}
              {invoice.partyPhone && <div style={{ fontSize: "10px" }}>Phone: {invoice.partyPhone}</div>}
            </div>
            <div style={{ textAlign: "right", fontSize: "10px" }}>
              {invoice.isInterState ? (
                <div>Inter-State Supply (IGST)</div>
              ) : (
                <div>Intra-State Supply (CGST + SGST)</div>
              )}
            </div>
          </div>
        </div>

        <table style={{ width: "100%", borderCollapse: "collapse", marginBottom: "10px", fontSize: `${Math.max(template.fontSize - 1, 8)}px` }}>
          <thead>
            <tr style={{ backgroundColor: "#f0f0f0" }}>
              <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "left", width: "30px" }}>#</th>
              <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "left" }}>Item Description</th>
              {template.showHsnCode && <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "left", width: "70px" }}>HSN</th>}
              <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "right", width: "50px" }}>Qty</th>
              <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "right", width: "70px" }}>Rate</th>
              {template.showTaxBreakup && (
                <>
                  <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "right", width: "50px" }}>Disc%</th>
                  <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "right", width: "50px" }}>Tax%</th>
                </>
              )}
              <th style={{ border: "1px solid black", padding: "4px 6px", textAlign: "right", width: "85px" }}>Amount</th>
            </tr>
          </thead>
          <tbody>
            {invoice.items.map((item, index) => (
              <tr key={item.id || index}>
                <td style={{ border: "1px solid black", padding: "3px 6px" }}>{index + 1}</td>
                <td style={{ border: "1px solid black", padding: "3px 6px" }}>
                  <div style={{ fontWeight: 500 }}>{item.itemName}</div>
                  {template.showItemCode && item.itemCode && (
                    <div style={{ fontSize: "9px", color: "#666" }}>Code: {item.itemCode}</div>
                  )}
                  {item.barcode && (
                    <div style={{ fontSize: "9px", color: "#666" }}>BC: {item.barcode}</div>
                  )}
                </td>
                {template.showHsnCode && (
                  <td style={{ border: "1px solid black", padding: "3px 6px" }}>{item.hsnCode}</td>
                )}
                <td style={{ border: "1px solid black", padding: "3px 6px", textAlign: "right" }}>{item.quantity}</td>
                <td style={{ border: "1px solid black", padding: "3px 6px", textAlign: "right" }}>₹{item.rate.toFixed(2)}</td>
                {template.showTaxBreakup && (
                  <>
                    <td style={{ border: "1px solid black", padding: "3px 6px", textAlign: "right" }}>{item.discountPercent || 0}%</td>
                    <td style={{ border: "1px solid black", padding: "3px 6px", textAlign: "right" }}>{item.taxPercent || 0}%</td>
                  </>
                )}
                <td style={{ border: "1px solid black", padding: "3px 6px", textAlign: "right", fontWeight: 500 }}>₹{item.amount.toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>

        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <div style={{ flex: 1, paddingRight: "15px" }}>
            {template.showBankDetails && template.bankDetails && (
              <div style={{ marginBottom: "10px" }}>
                <div style={{ fontWeight: 700, marginBottom: "4px", fontSize: "10px" }}>Bank Details:</div>
                <div style={{ whiteSpace: "pre-line", fontSize: "9px" }}>{template.bankDetails}</div>
              </div>
            )}
            {template.termsAndConditions && (
              <div style={{ fontSize: "8px" }}>
                <div style={{ fontWeight: 700, marginBottom: "2px" }}>Terms & Conditions:</div>
                <div style={{ whiteSpace: "pre-line" }}>{template.termsAndConditions}</div>
              </div>
            )}
          </div>
          <div style={{ width: "220px", border: "1px solid black", fontSize: "11px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
              <span>Subtotal:</span>
              <span>₹{invoice.subtotal.toFixed(2)}</span>
            </div>
            {invoice.totalDiscount > 0 && (
              <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
                <span>Discount:</span>
                <span>- ₹{invoice.totalDiscount.toFixed(2)}</span>
              </div>
            )}
            {template.showTaxBreakup && (
              invoice.isInterState ? (
                <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
                  <span>IGST:</span>
                  <span>₹{invoice.totalIgst.toFixed(2)}</span>
                </div>
              ) : (
                <>
                  <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
                    <span>CGST:</span>
                    <span>₹{invoice.totalCgst.toFixed(2)}</span>
                  </div>
                  <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
                    <span>SGST:</span>
                    <span>₹{invoice.totalSgst.toFixed(2)}</span>
                  </div>
                </>
              )
            )}
            {invoice.roundOff !== 0 && (
              <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", borderBottom: "1px solid black" }}>
                <span>Round Off:</span>
                <span>{invoice.roundOff >= 0 ? "+" : ""}₹{invoice.roundOff.toFixed(2)}</span>
              </div>
            )}
            <div style={{ display: "flex", justifyContent: "space-between", padding: "6px 8px", fontWeight: 700, fontSize: "14px", backgroundColor: "#f0f0f0" }}>
              <span>Grand Total:</span>
              <span>₹{invoice.grandTotal.toFixed(2)}</span>
            </div>
          </div>
        </div>

        {template.showPartyBalance && invoice.currentBalance !== undefined && (
          <div style={{ marginTop: "12px", border: "1px solid black", padding: "8px" }}>
            <div style={{ fontWeight: 700, marginBottom: "4px", fontSize: "10px" }}>Account Summary:</div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: "10px" }}>
              <span>Previous Balance:</span>
              <span>₹{(invoice.previousBalance || 0).toFixed(2)}</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontSize: "10px" }}>
              <span>Current Bill:</span>
              <span>₹{invoice.grandTotal.toFixed(2)}</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 700, borderTop: "1px solid black", paddingTop: "4px", marginTop: "4px", fontSize: "11px" }}>
              <span>Outstanding Balance:</span>
              <span>₹{invoice.currentBalance.toFixed(2)}</span>
            </div>
          </div>
        )}

        {/* E-Invoice Section - For B2B invoices */}
        {invoice.saleType === "B2B" && (
          invoice.irn ? (
            <div style={{ marginTop: "12px", border: "2px solid #000", padding: "10px", backgroundColor: "#f9f9f9" }}>
              <div style={{ fontWeight: 700, marginBottom: "8px", fontSize: "12px", textAlign: "center", borderBottom: "1px solid #000", paddingBottom: "4px" }}>
                e-Invoice Details
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                <div style={{ flex: 1, fontSize: "10px" }}>
                  <div style={{ marginBottom: "4px" }}>
                    <span style={{ fontWeight: 600 }}>IRN: </span>
                    <span style={{ fontFamily: "monospace", fontSize: "9px", wordBreak: "break-all" }}>{invoice.irn}</span>
                  </div>
                  <div style={{ marginBottom: "4px" }}>
                    <span style={{ fontWeight: 600 }}>Ack. No: </span>
                    <span style={{ fontFamily: "monospace" }}>{invoice.ackNumber}</span>
                  </div>
                  {invoice.ackDate && (
                    <div>
                      <span style={{ fontWeight: 600 }}>Ack. Date: </span>
                      <span>{format(new Date(invoice.ackDate), "dd/MM/yyyy HH:mm:ss")}</span>
                    </div>
                  )}
                </div>
                {invoice.qrCode && (
                  <div style={{ marginLeft: "15px", textAlign: "center" }}>
                    <img 
                      src={invoice.qrCode.startsWith('data:') ? invoice.qrCode : `data:image/png;base64,${invoice.qrCode}`}
                      alt="e-Invoice QR Code"
                      style={{ width: "80px", height: "80px", border: "1px solid #000" }}
                    />
                    <div style={{ fontSize: "8px", marginTop: "2px" }}>Scan for e-Invoice</div>
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div style={{ marginTop: "12px", border: "2px dashed #999", padding: "10px", backgroundColor: "#fff9e6", textAlign: "center" }}>
              <div style={{ fontWeight: 600, fontSize: "11px", color: "#b45309" }}>
                ⚠ e-Invoice Pending
              </div>
              <div style={{ fontSize: "9px", color: "#92400e", marginTop: "4px" }}>
                This B2B invoice requires e-Invoice registration on the GST portal
              </div>
            </div>
          )
        )}

        {template.footerText && (
          <div style={{ marginTop: "15px", textAlign: "center", borderTop: "1px solid black", paddingTop: "10px" }}>
            <div style={{ whiteSpace: "pre-line", fontSize: "10px" }}>{template.footerText}</div>
          </div>
        )}

        <div style={{ marginTop: "25px", display: "flex", justifyContent: "space-between" }}>
          <div style={{ textAlign: "center" }}>
            <div style={{ borderTop: "1px solid black", width: "120px", paddingTop: "4px", fontSize: "9px" }}>Customer Signature</div>
          </div>
          <div style={{ textAlign: "center" }}>
            <div style={{ borderTop: "1px solid black", width: "120px", paddingTop: "4px", fontSize: "9px" }}>Authorized Signatory</div>
          </div>
        </div>
      </div>
    );
  }
);

InvoiceA4Print.displayName = "InvoiceA4Print";

export const InvoiceB4CenteredPrint = forwardRef<HTMLDivElement, InvoicePrintProps>(
  ({ invoice, template, companyName, companyAddress, companyGst, companyPhone }, ref) => {
    return (
      <div
        ref={ref}
        className="bg-white text-black"
        style={{
          width: "210mm",
          minHeight: "297mm",
          display: "flex",
          justifyContent: "center",
          alignItems: "flex-start",
          paddingTop: "10mm",
          boxSizing: "border-box",
        }}
      >
        <style>
          {`
            @media print {
              @page { size: A4 portrait; margin: 5mm; }
              body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
