              <div style={{ display: "flex", justifyContent: "space-between", padding: "4px 6px", fontWeight: 700, fontSize: "12px", backgroundColor: "#f0f0f0" }}>
                <span>Total:</span><span>₹{invoice.grandTotal.toFixed(2)}</span>
