import { useState, useRef } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Wallet, Search, Printer, ArrowDownCircle, ArrowUpCircle, FileSpreadsheet, FileDown } from "lucide-react";
import { exportToExcel, exportToPDF, formatCurrency, formatDate } from "@/lib/export-utils";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { useReactToPrint } from "react-to-print";
import { useCompany } from "@/contexts/CompanyContext";
import { format } from "date-fns";

interface PaymentReport {
  id: number;
  date: string;
  type: string;
  partyId: number | null;
  partyName: string | null;
  amount: string;
  details: string | null;
}

function PaymentsReportPrint({ 
  payments, 
  totals, 
  companyName, 
  dateRange,
  paymentType 
}: { 
  payments: PaymentReport[]; 
  totals: { received: number; paid: number; net: number };
  companyName: string;
  dateRange: string;
  paymentType: string;
}) {
  return (
    <div className="p-8 bg-white text-black">
      <div className="text-center mb-6">
        <h1 className="text-xl font-bold">{companyName}</h1>
        <h2 className="text-lg font-semibold">Payment Report</h2>
        <p className="text-sm text-gray-600">{dateRange}</p>
        {paymentType && <p className="text-sm text-gray-600">Type: {paymentType}</p>}
      </div>

      <div className="grid grid-cols-3 gap-4 mb-6 text-center">
        <div className="border p-2">
          <p className="text-sm text-gray-600">Total Received</p>
          <p className="text-lg font-bold text-green-600">₹{totals.received.toFixed(2)}</p>
        </div>
        <div className="border p-2">
          <p className="text-sm text-gray-600">Total Paid</p>
          <p className="text-lg font-bold text-red-600">₹{totals.paid.toFixed(2)}</p>
        </div>
        <div className="border p-2">
          <p className="text-sm text-gray-600">Net Balance</p>
          <p className={`text-lg font-bold ${totals.net >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            ₹{totals.net.toFixed(2)}
          </p>
        </div>
      </div>

      <table className="w-full border-collapse text-sm">
        <thead>
          <tr className="border-b-2 border-black">
            <th className="text-left py-1 px-1">Date</th>
            <th className="text-left py-1 px-1">Type</th>
            <th className="text-left py-1 px-1">Party</th>
            <th className="text-left py-1 px-1">Details</th>
            <th className="text-right py-1 px-1">Amount</th>
          </tr>
        </thead>
        <tbody>
          {payments.map((payment, idx) => (
            <tr key={idx} className="border-b border-gray-200">
              <td className="py-1 px-1">{format(new Date(payment.date), "dd/MM/yyyy")}</td>
              <td className="py-1 px-1">
                <span className={payment.type === "RECEIVED" ? "text-green-600" : "text-red-600"}>
                  {payment.type}
                </span>
              </td>
              <td className="py-1 px-1">{payment.partyName || "Cash"}</td>
              <td className="py-1 px-1">{payment.details || "—"}</td>
              <td className="text-right py-1 px-1 font-mono">
                {parseFloat(payment.amount).toFixed(2)}
              </td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className="border-t-2 border-black font-bold">
            <td colSpan={4} className="py-2 px-1">Total ({payments.length} transactions)</td>
            <td className="text-right py-2 px-1">
              ₹{payments.reduce((sum, p) => sum + parseFloat(p.amount), 0).toFixed(2)}
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
}

export default function PaymentsReport() {
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [paymentType, setPaymentType] = useState("all");
  const printRef = useRef<HTMLDivElement>(null);
  const { currentCompany } = useCompany();

  // Build query params as URL search params
  const queryParams = new URLSearchParams();
  if (startDate) queryParams.set("startDate", startDate);
  if (endDate) queryParams.set("endDate", endDate);
  if (paymentType !== "all") queryParams.set("type", paymentType);

  const queryString = queryParams.toString();
  const apiUrl = queryString ? `/api/reports/payments?${queryString}` : "/api/reports/payments";

  const { data: payments, isLoading } = useQuery<PaymentReport[]>({
    queryKey: ["/api/reports/payments", startDate, endDate, paymentType],
    queryFn: async () => {
      const res = await fetch(apiUrl, { credentials: "include", headers: { "X-Company-Id": localStorage.getItem("currentCompanyId") || "" } });
      if (!res.ok) throw new Error("Failed to fetch payments report");
      return res.json();
    },
  });

  const handlePrint = useReactToPrint({
    contentRef: printRef,
    documentTitle: `Payments-Report-${format(new Date(), "yyyy-MM-dd")}`,
  });

  const handleExcelExport = () => {
    if (!filteredPayments?.length) return;

    exportToExcel({
      title: "Payment Report",
      filename: `Payment-Report-${format(new Date(), "yyyy-MM-dd")}`,
      dateRange: { start: startDate, end: endDate },
      filters: paymentType === "all" ? "All Types" : paymentType,
      columns: [
        { header: "Date", key: "date", width: 12 },
        { header: "Type", key: "type", width: 10 },
        { header: "Party", key: "partyName", width: 25 },
        { header: "Details", key: "details", width: 30 },
        { header: "Amount", key: "amount", width: 12, format: formatCurrency },
      ],
      data: filteredPayments.map(payment => ({
        date: formatDate(payment.date),
        type: payment.type,
        partyName: payment.partyName || "Cash",
        details: payment.details || "",
        amount: payment.amount,
      })),
      summary: {
        label: "Total",
        values: ["", "", "", payments?.reduce((sum, p) => sum + parseFloat(p.amount), 0).toFixed(2) || "0.00"],
      },
    });
  };

  const handlePDFExport = () => {
    if (!filteredPayments?.length) return;

    exportToPDF({
      title: "Payment Report",
      filename: `Payment-Report-${format(new Date(), "yyyy-MM-dd")}`,
      dateRange: { start: startDate, end: endDate },
      filters: paymentType === "all" ? "All Types" : paymentType,
      columns: [
        { header: "Date", key: "date", width: 12 },
        { header: "Type", key: "type", width: 10 },
        { header: "Party", key: "partyName", width: 25 },
        { header: "Details", key: "details", width: 30 },
        { header: "Amount", key: "amount", width: 12, format: formatCurrency },
      ],
      data: filteredPayments.map(payment => ({
        date: formatDate(payment.date),
        type: payment.type,
        partyName: payment.partyName || "Cash",
        details: payment.details || "",
        amount: payment.amount,
      })),
      summary: {
        label: "Total",
        values: ["", "", "", payments?.reduce((sum, p) => sum + parseFloat(p.amount), 0).toFixed(2) || "0.00"],
      },
    });
  };

  const filteredPayments = payments?.filter((payment) =>
    (payment.partyName?.toLowerCase().includes(searchQuery.toLowerCase())) ||
    (payment.details?.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  const totals = filteredPayments?.reduce(
    (acc, payment) => {
      const amount = parseFloat(payment.amount);
      if (payment.type === "RECEIVED") {
        acc.received += amount;
      } else {
        acc.paid += amount;
      }
      acc.net = acc.received - acc.paid;
      return acc;
    },
    { received: 0, paid: 0, net: 0 }
  ) || { received: 0, paid: 0, net: 0 };

  const dateRange = startDate && endDate 
    ? `${format(new Date(startDate), "dd/MM/yyyy")} to ${format(new Date(endDate), "dd/MM/yyyy")}`
    : "All Time";

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Payment Report</h1>
          <p className="text-muted-foreground mt-2">
            Date-wise payment transactions
          </p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <Button variant="outline" onClick={handleExcelExport} disabled={!filteredPayments?.length} data-testid="button-export-excel">
            <FileSpreadsheet className="mr-2 h-4 w-4" />
            Excel
          </Button>
          <Button variant="outline" onClick={handlePDFExport} disabled={!filteredPayments?.length} data-testid="button-export-pdf">
            <FileDown className="mr-2 h-4 w-4" />
            PDF
          </Button>
          <Button variant="outline" onClick={() => handlePrint()} disabled={!filteredPayments?.length} data-testid="button-print-payments-report">
            <Printer className="h-4 w-4 mr-2" />
            Print
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Filters</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4 sm:grid-cols-4">
            <div className="space-y-2">
              <Label htmlFor="startDate">Start Date</Label>
              <Input
                id="startDate"
                type="date"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                data-testid="input-start-date"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="endDate">End Date</Label>
              <Input
                id="endDate"
                type="date"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                data-testid="input-end-date"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="paymentType">Payment Type</Label>
              <Select value={paymentType} onValueChange={setPaymentType} data-testid="select-payment-type">
                <SelectTrigger id="paymentType">
                  <SelectValue placeholder="All Types" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Types</SelectItem>
                  <SelectItem value="RECEIVED">Received</SelectItem>
                  <SelectItem value="PAID">Paid</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="search">Search</Label>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  id="search"
                  placeholder="Party or details..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9"
                  data-testid="input-search-payments"
                />
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="grid gap-6 sm:grid-cols-3">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Received</CardTitle>
            <ArrowDownCircle className="h-4 w-4 text-green-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold font-mono text-green-600" data-testid="text-total-received">
              ₹{totals.received.toFixed(2)}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Paid</CardTitle>
            <ArrowUpCircle className="h-4 w-4 text-red-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold font-mono text-red-600" data-testid="text-total-paid">
              ₹{totals.paid.toFixed(2)}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between gap-2 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Net Balance</CardTitle>
            <Wallet className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className={`text-2xl font-semibold font-mono ${totals.net >= 0 ? 'text-green-600' : 'text-red-600'}`} data-testid="text-net-balance">
              ₹{totals.net.toFixed(2)}
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Payment Transactions</CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-3">
              {[...Array(5)].map((_, i) => (
                <Skeleton key={i} className="h-12 w-full" />
              ))}
            </div>
          ) : filteredPayments && filteredPayments.length > 0 ? (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Date</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Party</TableHead>
                  <TableHead>Details</TableHead>
                  <TableHead className="text-right">Amount</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredPayments.map((payment) => (
                  <TableRow key={payment.id} data-testid={`row-payment-${payment.id}`}>
                    <TableCell>{format(new Date(payment.date), "dd/MM/yyyy")}</TableCell>
                    <TableCell>
                      {payment.type === "RECEIVED" ? (
                        <Badge variant="default" className="bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200">
                          <ArrowDownCircle className="h-3 w-3 mr-1" />
                          Received
                        </Badge>
                      ) : (
                        <Badge variant="default" className="bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200">
                          <ArrowUpCircle className="h-3 w-3 mr-1" />
                          Paid
                        </Badge>
                      )}
                    </TableCell>
                    <TableCell>{payment.partyName || "Cash"}</TableCell>
                    <TableCell className="text-muted-foreground">{payment.details || "—"}</TableCell>
                    <TableCell className="text-right font-mono font-medium">
                      ₹{parseFloat(payment.amount).toFixed(2)}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          ) : (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <Wallet className="h-12 w-12 text-muted-foreground/50 mb-4" />
              <p className="text-sm text-muted-foreground">
                {searchQuery ? "No payments found" : "No payment data for selected period"}
              </p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Hidden print container */}
      <div style={{ position: 'absolute', left: '-9999px', top: '0' }}>
        <div ref={printRef}>
          <PaymentsReportPrint
            payments={filteredPayments || []}
            totals={totals}
            companyName={currentCompany?.name || "Company"}
            dateRange={dateRange}
            paymentType={paymentType === "all" ? "" : paymentType}
          />
        </div>
      </div>
    </div>
  );
}

client/src/hooks/use-print-settings.ts.content:
import { useState, useEffect, useCallback } from "react";
import { apiRequest } from "@/lib/queryClient";

export interface PrintSettings {
  autoPrintB2B: boolean;
  autoPrintB2C: boolean;
  autoPrintEstimate: boolean;
  autoPrintCreditNote: boolean;
  autoPrintDebitNote: boolean;
  printCopiesB2B: number;
  printCopiesB2C: number;
  printCopiesEstimate: number;
  printCopiesCreditNote: number;
  printCopiesDebitNote: number;
  showPrintConfirmation: boolean;
  defaultPrinterName: string;
  enableTamilPrint: boolean;
  directPrintB2B: boolean;
  directPrintB2C: boolean;
  directPrintEstimate: boolean;
  directPrintCreditNote: boolean;
  directPrintDebitNote: boolean;
  enableWebSocketPrint: boolean;
  webSocketPrinterName: string;
}

const DEFAULT_PRINT_SETTINGS: PrintSettings = {
  autoPrintB2B: false,
  autoPrintB2C: true,
  autoPrintEstimate: false,
  autoPrintCreditNote: false,
  autoPrintDebitNote: false,
  printCopiesB2B: 2,
  printCopiesB2C: 1,
  printCopiesEstimate: 1,
  printCopiesCreditNote: 2,
  printCopiesDebitNote: 2,
  showPrintConfirmation: true,
  defaultPrinterName: "",
  enableTamilPrint: false,
  directPrintB2B: false,
  directPrintB2C: false,
  directPrintEstimate: false,
  directPrintCreditNote: false,
  directPrintDebitNote: false,
  enableWebSocketPrint: false,
  webSocketPrinterName: "",
};

export function usePrintSettings() {
  const [settings, setSettings] = useState<PrintSettings>(DEFAULT_PRINT_SETTINGS);
  const [loading, setLoading] = useState(true);

  // Load settings from server on mount
  useEffect(() => {
    const loadSettings = async () => {
      try {
        const response = await apiRequest("GET", "/api/print-settings");
        const data = await response.json();
        setSettings({ ...DEFAULT_PRINT_SETTINGS, ...data });
      } catch (error) {
        console.error("Failed to load print settings:", error);
        setSettings(DEFAULT_PRINT_SETTINGS);
      } finally {
        setLoading(false);
      }
    };
    loadSettings();
  }, []);

  const shouldAutoPrint = useCallback((billType: string): boolean => {
    switch (billType) {
      case "B2B":
        return settings.autoPrintB2B;
      case "B2C":
        return settings.autoPrintB2C;
      case "EST":
        return settings.autoPrintEstimate;
      case "CN":
        return settings.autoPrintCreditNote;
      case "DN":
        return settings.autoPrintDebitNote;
      default:
        return false;
    }
  }, [settings]);

  const getPrintCopies = useCallback((billType: string): number => {
    switch (billType) {
      case "B2B":
        return settings.printCopiesB2B;
      case "B2C":
        return settings.printCopiesB2C;
      case "EST":
        return settings.printCopiesEstimate;
      case "CN":
        return settings.printCopiesCreditNote;
      case "DN":
        return settings.printCopiesDebitNote;
      default:
        return 1;
    }
  }, [settings]);

  const shouldDirectPrint = useCallback((billType: string): boolean => {
    switch (billType) {
      case "B2B":
        return settings.directPrintB2B;
      case "B2C":
        return settings.directPrintB2C;
      case "EST":
        return settings.directPrintEstimate;
      case "CN":
        return settings.directPrintCreditNote;
      case "DN":
        return settings.directPrintDebitNote;
      default:
        return false;
    }
  }, [settings]);

  // Deprecated: Direct WebSocket print is now handled server-side via /api/print/send
  const sendDirectPrint = useCallback(async (saleId: number): Promise<boolean> => {
    console.log("sendDirectPrint is deprecated - use invoice page's handleWebSocketPrint instead");
    return false;
  }, []);

  return {
    settings,
    setSettings,
    loading,
    shouldAutoPrint,
    getPrintCopies,
    shouldDirectPrint,
    sendDirectPrint,
    showConfirmation: settings.showPrintConfirmation,
    enableTamilPrint: settings.enableTamilPrint,
  };
}

export async function savePrintSettings(settings: PrintSettings): Promise<void> {
  try {
    await apiRequest("POST", "/api/print-settings", settings);
  } catch (error) {
    console.error("Failed to save print settings:", error);
    throw error;
  }
}

